INSERT INTO `assistant_memory` VALUES (1,3,'CONTEXT','SESSION_CONTEXT','最近会话上下文','当前上下文类型为 MATERIAL，关联资料ID=8；最近一次助手响应：这份《docker_practice-v1.7.5》的核心知识点是分阶段递进设计的，主要分为四大模块：1.基础入门模块：容器和虚拟机的差异、Docker三大核心概念、Docker基础操作命令，是入门首先要掌握的内容2.镜像与编排实践模块：Dockerfile核心指令、多阶段构建方法、镜像优化技巧，还','当前上下文类型为 MATERIAL，关联资料ID=8','ASSISTANT_SESSION',21,60.00,80.00,65,'2026-04-20 14:39:48','PENDING',NULL,NULL,NULL,'2026-04-18 13:05:51','2026-04-18 13:05:51');
