  int age;\\r\\n    // 成员方法（行为）\",\"keywords\":null,\"score\":0.22591738},{\"segmentId\":53,\"segmentNo\":19,\"pageNo\":16,\"sectionTitle\":\"第16页 · 第1段 · 七、多线程（约 600 字）\",\"contentText\":\"七、多线程（约 600 字）\\r\\n7.1 线程概念\\r\\n线程是程序执行的最小单位，一个进程可包含多个线程，多线程可并发执行，提高程序效率。\\r\\n7.2 线程创建方式\\r\\n7.2.1 继承 Thread 类\\r\\nclass MyThread extends Thread {\\r\\n    @Override\\r\\n    public void run() {\\r\\n        // 线程执行逻辑\\r\\n        for (int i = 0; i < 10; i++) {\\r\\n            System.out.println(Thread.currentThread().getName() + \\\":\\\" + i);\\r\\n            try {\\r\\n                Thread.sleep(100); // 线程休眠100毫秒\\r\\n            } catch (InterruptedException e) {\\r\\n                e.printStackTrace();\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        MyThread thread1 = new MyThread();\\r\\n        MyThread thread2 = new MyThread();\\r\\n        thread1.setName(\\\"线程1\\\");\\r\\n        thread2.setName(\\\"线程2\\\");\\r\\n        thread1.start(); // 启动线程（调用run方法）\\r\\n        thread2.start();\\r\\n    }\\r\\n}\",\"keywords\":null,\"score\":0.221484},{\"segmentId\":37,\"segmentNo\":3,\"pageNo\":3,\"sectionTitle\":\"第3页 · 第1段 · // if-else语句\",\"contentText\":\"// if-else语句\\r\\nif (age >= 18) {\\r\\n    System.out.println(\\\"成年人\\\");\\r\\n} else if (age >= 6) {\\r\\n    System.out.println(\\\"青少年\\\");\\r\\n} else {\\r\\n    System.out.println(\\\"儿童\\\");\\r\\n}\\r\\n// switch语句（JDK7+支持String类型）\\r\\nswitch (season) {\\r\\n    case \\\"春季\\\":\\r\\n        System.out.println(\\\"3-5月\\\");\\r\\n        break;\\r\\n    case \\\"夏季\\\":\\r\\n        System.out.println(\\\"6-8月\\\");\\r\\n        break;\\r\\n    default:\\r\\n        System.out.println(\\\"未知季节\\\");\\r\\n}\\r\\n2.4.2 循环语句\\r\\n// for循环\\r\\nfor (int i = 0; i  i++) {\\r\\n    System.out.println(i); // 输出0-9\\r\\n}\\r\\n// while循环\\r\\nint j = 0;\\r\\nwhile (j 0) {\\r\\n    System.out.println(j);\\r\\n    j++;\\r\\n}\\r\\n// do-while循环（至少执行一次）\\r\\nint k = 0;\\r\\ndo {\\r\\n    System.out.println(k);\\r\\n    k++;\\r\\n} while (k < 10);\",\"keywords\":null,\"score\":0.21803345},{\"segmentId\":54,\"segmentNo\":20,\"pageNo\":17,\"sectionTitle\":\"第17页 · 第1段 · 7.2.2 实现 Runnable 接口\",\"contentText\":\"7.2.2 实现 Runnable 接口\\r\\nclass MyRunnable implements Runnable {\\r\\n    @Override\\r\\n    public void run() {\\r\\n        for (int i = 0; i  i++) {\\r\\n            System.out.println(Thread.currentThread().getName() + \\\":\\\" + i);\\r\\n            try {\\r\\n                Thread.sleep(100);\\r\\n            } catch (InterruptedException e) {\\r\\n                e.printStackTrace();\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Thread thread1 = new Thread(new MyRunnable(), \\\"线程1\\\");\\r\\n        Thread thread2 = new Thread(new MyRunnable(), \\\"线程2\\\");\\r\\n        thread1.start();\\r\\n        thread2.start();\\r\\n    }\\r\\n}\\r\\n7.2.3 实现 Callable 接口（带返回值）\\r\\nclass MyCallable implements Callable\\r\\n    @Override\\r\\n    public Integer call() throws Exception {\\r\\n        int sum = 0;\\r\\n        for (int i = 1; i 0; i++) {\\r\\n            sum += i;\\r\\n        }\\r\\n        return sum; // 返回结果\",\"keywords\":null,\"score\":0.21244246},{\"segmentId\":56,\"segmentNo\":22,\"pageNo\":18,\"sectionTitle\":\"第18页 · 第1段 · public class Test {\",\"contentText\":\"public class Test {\\r\\n    public static void main(String[] args) throws ExecutionException, InterruptedException {\\r\\n        Callable = new MyCallable();\\r\\n        FutureTaskTask = new FutureTaskcallable);\\r\\n        new Thread(futureTask).start();\\r\\n        Integer result = futureTask.get(); // 获取返回值（阻塞等待）\\r\\n        System.out.println(\\\"1-100求和：\\\" + result); // 输出：5050\\r\\n    }\\r\\n}\\r\\n7.3 线程状态与控制\\r\\n线程生命周期包括：新建（New）、就绪（Runnable）、运行（Running）、阻塞（Blocked）、死\\