"payloadJson\":\"{\\\"materialId\\\":5,\\\"modelName\\\":null,\\\"title\\\":null,\\\"questionCount\\\":5,\\\"singleCount\\\":5,\\\"judgeCount\\\":0,\\\"shortAnswerCount\\\":0,\\\"difficultyLevel\\\":3}\",\"resultJson\":null,\"errorMessage\":null,\"startedAt\":null,\"finishedAt\":null,\"createdAt\":\"2026-04-18T20:07:32.2837324\",\"updatedAt\":\"2026-04-18T20:07:32.2837324\"}','SUCCESS',NULL,'2026-04-18 20:07:32','2026-04-18 20:07:32','2026-04-18 20:07:32','2026-04-18 20:07:32'),(46,14,99,'material.list','{\"keyword\":null,\"limit\":6,\"embeddingReadyOnly\":false}','{\"keyword\":null,\"embeddingReadyOnly\":false,\"total\":4,\"size\":6,\"records\":[{\"id\":8,\"title\":\"docker_practice-v1.7.5\",\"materialType\":\"PDF\",\"parseStatus\":\"SUCCESS\",\"summaryStatus\":\"PENDING\",\"difficultyLevel\":3,\"tags\":null,\"totalCharacters\":468047,\"embeddingStatus\":\"SUCCESS\",\"embeddedSegmentCount\":867,\"totalSegmentCount\":867,\"lastStudyTime\":null,\"createdAt\":\"2026-04-17T19:39:05\"},{\"id\":7,\"title\":\"Java核心知识全面梳理\",\"materialType\":\"PDF\",\"parseStatus\":\"SUCCESS\",\"summaryStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"tags\":null,\"totalCharacters\":15837,\"embeddingStatus\":\"SUCCESS\",\"embeddedSegmentCount\":26,\"totalSegmentCount\":26,\"lastStudyTime\":null,\"createdAt\":\"2026-04-17T19:07:24\"},{\"id\":6,\"title\":\"Java核心知识全面梳理\",\"materialType\":\"PDF\",\"parseStatus\":\"SUCCESS\",\"summaryStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"tags\":null,\"totalCharacters\":15837,\"embeddingStatus\":\"SUCCESS\",\"embeddedSegmentCount\":17,\"totalSegmentCount\":17,\"lastStudyTime\":null,\"createdAt\":\"2026-04-17T11:40:55\"},{\"id\":5,\"title\":\"计算机网络核心知识全解析（2026版）\",\"materialType\":\"PDF\",\"parseStatus\":\"SUCCESS\",\"summaryStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"tags\":null,\"totalCharacters\":4866,\"embeddingStatus\":\"SUCCESS\",\"embeddedSegmentCount\":5,\"totalSegmentCount\":5,\"lastStudyTime\":null,\"createdAt\":\"2026-04-16T17:26:09\"}]}','SUCCESS'