rMessage\":null,\"startedAt\":null,\"finishedAt\":null,\"createdAt\":\"2026-04-20T14:11:17.3781925\",\"updatedAt\":\"2026-04-20T14:11:17.3781925\"}','SUCCESS',NULL,'2026-04-20 14:11:17','2026-04-20 14:11:17','2026-04-20 14:11:17','2026-04-20 14:11:17'),(55,18,121,'material.search','{\"queryText\":\"Java核心知识全面梳理\",\"limit\":5}','{\"queryText\":\"Java核心知识全面梳理\",\"selectedMaterialId\":null,\"selectedMaterialTitle\":null,\"needsClarification\":true,\"candidates\":[{\"id\":7,\"title\":\"Java核心知识全面梳理\",\"materialType\":\"PDF\",\"parseStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"totalCharacters\":15837,\"tags\":null,\"matchScore\":100},{\"id\":6,\"title\":\"Java核心知识全面梳理\",\"materialType\":\"PDF\",\"parseStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"totalCharacters\":15837,\"tags\":null,\"matchScore\":100}]}','WAITING',NULL,'2026-04-20 14:18:43','2026-04-20 14:18:43','2026-04-20 14:18:43','2026-04-20 14:18:43'),(56,18,123,'material.select','{\"materialId\":7}','{\"materialId\":7,\"materialTitle\":\"Java核心知识全面梳理\"}','SUCCESS',NULL,'2026-04-20 14:19:24','2026-04-20 14:19:24','2026-04-20 14:19:38','2026-04-20 14:19:38'),(57,18,123,'material.detail','{\"materialId\":7}','{\"id\":7,\"title\":\"Java核心知识全面梳理\",\"materialType\":\"PDF\",\"sourceType\":\"UPLOAD\",\"fileName\":\"Java核心知识全面梳理.pdf\",\"fileUrl\":\"C:\\\\Users\\\\雪\\\\Desktop\\\\AI-Intelligent-Learning-Assistant-System\\\\backend\\\\uploads\\\\cb6c96d4-a5bf-4e78-ac4e-5192b399b19a.pdf\",\"fileSize\":221847,\"parseStatus\":\"SUCCESS\",\"summaryStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"tags\":null,\"totalPages\":20,\"totalCharacters\":15837,\"embeddingStatus\":\"SUCCESS\",\"embeddedSegmentCount\":26,\"totalSegmentCount\":26,\"lastStudyTime\":null,\"createdAt\":\"2026-04-17T19:07:24\",\"segments\":[{\"id\":35,\"segmentNo\":1,\"pageNo\":1,\"sectionTitle\":\"第1页 · 第1段 · Java 核心知识全面梳理\",\"contentText\":\"Java 核心知识全面梳理\\r\\n一、Java 语言概述（约 500 字）\\r\\n1.1 语言简介\\r\\nJava 是由 Sun Microsystems（后被 Oracle 收购）于 1995 年推出的面向对象编程语言，其设计理念是\\r\\n “一次编写，到处运行（Write Once, Run Anywhere, WORA）”。核心优势在于跨平台性，通过 Java\\r\\n 虚拟机（JVM）实现 ——Java 源代码编译为字节码（.class 文件），再由不同平台的 JVM 解释执行，\\r\\n无需修改代码即可在 Windows、Linux、macOS 等系统运行。\\r\\n1.2 主要特点\\r\\n◦ 面向对象：封装、继承、多态三大特性，符合现实世界建模逻辑；\\r\\n◦ 跨平台：依赖 JVM 屏蔽底层系统差异，字节码具备平台无关性；\\r\\n◦ 安全性：内置安全机制，避免指针直接操作，防止内存泄露和恶意攻击；\\r\\n◦ 健壮性：强类型检查、异常处理机制，提升程序稳定性；\\r\\n◦ 多线程：原生支持多线程编程，适合并发场景开发。\\r\\n1.3 应用场景\\r\\nJava 广泛应用于企业级开发（Spring、MyBatis 框架）、移动开发（Android 应用）、大数据处理（-\\r\\nHadoop 生态）、中间件开发（Tomcat、Nacos）等领域，是当前最主流的编程语言之一。\\r\\n二、Java 基础语法（约 800 字）\\r\\n2.1 数据类型\\r\\nJava 数据类型分为基本类型和引用类型，其中基本类型共 8 种：\\r\\n类型 占用空间 取值范围\"},{\"id\":36,\"segmentNo\":2,\"pageNo\":2,\"sectionTitle\":\"第2页 · 第1段 · byte 1 字节 -128 ~ 127\",\"contentText\":\"byte 1 字节 -128 ~ 127\\r\\nshort 2 字节 -32768 ~ 32767\\r\\nint 4 字节 -2³¹ ~ 2³¹-1\\r\\nlong 8 字节 -2v³ ~ 2v³-1\\r\\nfloat 4 字节 单精度浮点数，约 ±3.4e38\\r\\ndouble 8 字节 双精度浮点数，约 ±1.8e308\\r\\nchar 2 字节 Unicode 字符（0 ~ 65535）\\r\\nboolean 1 字节 true/false\\r\\n引用类型包括类、接口、数组、枚举等，本质是指向对象的内存地址。\\r\\n2.2 变量与常量\\r\\n◦ 变量：需声明数据类型，语法为类型 变量名 = 初始值;，如int age = 20;；\\r\\n◦ 常量：用final修饰，一旦赋值不可修改，语法为final 类型 常量名 = 值;，如final double PI = 3.\\r\\n14159;（常量名通常大写）。\\r\\n2.3 运算符\\r\\n◦ 算术运算符：+\\u0001-\\u0001*\\u0001/\\u0001%\\u0001++\\u0001--（注意++前置自增与后置自增的区别）；\\r\\n◦ 关系运算符：`==、!=、>、<、>=、返回 boolean 类型；\\r\\n◦ 逻辑运算符：&&（短路与）、||（短路或）、!（非）；\\r\\n◦ 赋值运算符：=\\u0001+=\\u0001-=\\u0001*=\\u0001/=等；\\r\\n◦ 三元运算符：条件表达式 ? 表达式1 : 表达式2，如int max = a > b ? a : b;。\\r\\n2.4 流程控制\\r\\n2.4.1 条件语句\"},{\"id\":37,\"segmentNo\":3,\"pageNo\":3,\"sectionTitle\":\"第3页 · 第1段 · // if-else语句\",\"contentText\":\"// if-else语句\\r\\nif (age >= 18) {\\r\\n    System.out.println(\\\"成年人\\\");\\r\\n} else if (age >= 6) {\\r\\n    System.out.println(\\\"青少年\\\");\\r\\n} else {\\r\\n    System.out.println(\\\"儿童\\\");\\r\\n}\\r\\n// switch语句（JDK7+支持String类型）\\r\\nswitch (season) {\\r\\n    case \\\"春季\\\":\\r\\n        System.out.println(\\\"3-5月\\\");\\r\\n        break;\\r\\n    case \\\"夏季\\\":\\r\\n        System.out.println(\\\"6-8月\\\");\\r\\n        break;\\r\\n    default:\\r\\n        System.out.println(\\\"未知季节\\\");\\r\\n}\\r\\n2.4.2 循环语句\\r\\n// for循环\\r\\nfor (int i = 0; i  i++) {\\r\\n    System.out.println(i); // 输出0-9\\r\\n}\\r\\n// while循环\\r\\nint j = 0;\\r\\nwhile (j 0) {\\r\\n    System.out.println(j);\\r\\n    j++;\\r\\n}\\r\\n// do-while循环（至少执行一次）\\r\\nint k = 0;\\r\\ndo {\\r\\n    System.out.println(k);\\r\\n    k++;\\r\\n} while (k < 10);\"},{\"id\":38,\"segmentNo\":4,\"pageNo\":4,\"sectionTitle\":\"第4页 · 第1段 · 2.5 数组\",\"contentText\":\"2.5 数组\\r\\n数组是存储同一类型数据的固定长度容器，声明与初始化方式：\\r\\n// 声明并初始化\\r\\nint[] arr1 = {1, 2, 3};\\r\\n// 指定长度初始化\\r\\nint[] arr2 = new int[3];\\r\\narr2[0] = 1;\\r\\narr2[1] = 2;\\r\\narr2[2] = 3;\\r\\n// 遍历数组（增强for循环）\\r\\nfor (int num : arr1) {\\r\\n    System.out.println(num);\\r\\n}\\r\\n三、面向对象编程（约 1000 字）\\r\\n3.1 核心概念\\r\\n面向对象编程（OOP）以 “对象” 为核心，将数据和行为封装为一个整体，通过继承和多态实现代码\\r\\n复用和扩展。\\r\\n3.2 类与对象\\r\\n◦ 类：对象的模板，定义对象的属性（成员变量）和行为（成员方法）；\\r\\n◦ 对象：类的实例化结果，通过new关键字创建。\\r\\n示例代码：\\r\\n// 定义Person类\\r\\nclass Person {\\r\\n    // 成员变量（属性）\\r\\n    String name;\\r\\n    int age;\\r\\n    // 成员方法（行为）\"},{\"id\":39,\"segmentNo\":5,\"pageNo\":5,\"sectionTitle\":\"第5页 · 第1段 ·     }\",\"contentText\":\"    public void eat() {\\r\\n        System.out.println(name + \\\"正在吃饭\\\");\\r\\n    }\\r\\n    public void sleep() {\\r\\n        System.out.println(name + \\\"正在睡觉\\\");\\r\\n    }\\r\\n}\\r\\n// 创建对象并使用\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Person person = new Person();\\r\\n        person.name = \\\"张三\\\";\\r\\n        person.age = 25;\\r\\n        person.eat(); // 输出：张三正在吃饭\\r\\n        person.sleep(); // 输出：张三正在睡觉\\r\\n    }\\r\\n}\\r\\n3.3 封装\\r\\n封装是将对象的属性私有化，通过公共的getter/setter方法控制访问，隐藏内部实现细节，提升安\\r\\n全性。\\r\\n示例代码：\\r\\nclass Person {\\r\\n    // 私有成员变量（仅本类可访问）\\r\\n    private String name;\\r\\n    private int age;\\r\\n    // getter方法（获取属性值）\\r\\n    public String getName() {\\r\\n        return name;\\r\\n    }\\r\\n    // setter方法（设置属性值，可添加逻辑校验）\\r\\n    public void setName(String name) {\\r\\n        if (name != null && !name.isEmpty()) {\\r\\n            this.name = name;\\r\\n        } else {\\r\\n            System.out.println(\\\"姓名不能为空\\\");\\r\\n        }\"},{\"id\":40,\"segmentNo\":6,\"pageNo\":6,\"sectionTitle\":\"第6页 · 第1段 ·     }\",\"contentText\":\"    }\\r\\n    public int getAge() {\\r\\n        return age;\\r\\n    }\\r\\n    public void setAge(int age) {\\r\\n        if (age >= 0 && age  120) {\\r\\n            this.age = age;\\r\\n        } else {\\r\\n            System.out.println(\\\"年龄无效\\\");\\r\\n        }\\r\\n    }\\r\\n}\\r\\n3.4 继承\\r\\n继承允许子类继承父类的属性和方法，子类可扩展新功能或重写父类方法，关键字为extends。Java \\r\\n支持单继承（一个子类只能有一个父类），但可通过接口实现多继承效果。\\r\\n示例代码：\\r\\n// 父类\\r\\nclass Animal {\\r\\n    public void move() {\\r\\n        System.out.println(\\\"动物会移动\\\");\\r\\n    }\\r\\n}\\r\\n// 子类继承父类\\r\\nclass Dog extends Animal {\\r\\n    // 重写父类方法\\r\\n    @Override\\r\\n    public void move() {\\r\\n        System.out.println(\\\"狗会跑\\\");\\r\\n    }\\r\\n    // 子类扩展方法\\r\\n    public void bark() {\\r\\n        System.out.println(\\\"狗会叫\\\");\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\"},{\"id\":41,\"segmentNo\":7,\"pageNo\":7,\"sectionTitle\":\"第7页 · 第1段 ·     public static void main(Stri\",\"contentText\":\"    public static void main(String[] args) {\\r\\n        Dog dog = new Dog();\\r\\n        dog.move(); // 输出：狗会跑（重写后）\\r\\n        dog.bark(); // 输出：狗会叫（扩展方法）\\r\\n    }\\r\\n}\\r\\n3.5 多态\\r\\n多态是指同一行为在不同对象上表现出不同形态，实现条件：\\r\\n1. 子类继承父类；\\r\\n2. 子类重写父类方法；\\r\\n3. 父类引用指向子类对象。\\r\\n示例代码：\\r\\nclass Animal {\\r\\n    public void sound() {\\r\\n        System.out.println(\\\"动物发出声音\\\");\\r\\n    }\\r\\n}\\r\\nclass Cat extends Animal {\\r\\n    @Override\\r\\n    public void sound() {\\r\\n        System.out.println(\\\"猫喵喵叫\\\");\\r\\n    }\\r\\n}\\r\\nclass Bird extends Animal {\\r\\n    @Override\\r\\n    public void sound() {\\r\\n        System.out.println(\\\"鸟叽叽叫\\\");\\r\\n    }\\r\\n}\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Animal animal1 = new Cat();\\r\\n        Animal animal2 = new Bird();\\r\\n        animal1.sound(); // 输出：猫喵喵叫\"},{\"id\":42,\"segmentNo\":8,\"pageNo\":8,\"sectionTitle\":\"第8页 · 第1段 ·     }\",\"contentText\":\"        animal2.sound(); // 输出：鸟叽叽叫\\r\\n    }\\r\\n}\\r\\n3.6 接口与抽象类\\r\\n◦ 抽象类：用abstract修饰，包含抽象方法（无实现）和普通方法，不能实例化，需子类继承并实现抽\\r\\n象方法；\\r\\n◦ 接口：用interface修饰，仅包含抽象方法（JDK8 + 支持默认方法和静态方法），类通过-\\r\\nimplements实现接口，可多实现。\\r\\n示例（接口）：\\r\\ninterface Flyable {\\r\\n    void fly(); // 抽象方法\\r\\n}\\r\\nclass Bird implements Flyable {\\r\\n    @Override\\r\\n    public void fly() {\\r\\n        System.out.println(\\\"鸟展翅飞翔\\\");\\r\\n    }\\r\\n}\\r\\nclass Plane implements Flyable {\\r\\n    @Override\\r\\n    public void fly() {\\r\\n        System.out.println(\\\"飞机引擎驱动飞行\\\");\\r\\n    }\\r\\n}\\r\\n四、Java 核心类库（约 600 字）\\r\\n4.1 String 类\\r\\nString 是不可变字符序列，常用方法：\"},{\"id\":43,\"segmentNo\":9,\"pageNo\":9,\"sectionTitle\":\"第9页 · 第1段 · String str = \\\"Hello Java\\\";\",\"contentText\":\"String str = \\\"Hello Java\\\";\\r\\nSystem.out.println(str.length()); // 长度：9\\r\\nSystem.out.println(str.charAt(0)); // 获取索引0字符：\'H\'\\r\\nSystem.out.println(str.substring(6)); // 截取子串：\\\"Java\\\"\\r\\nSystem.out.println(str.equals(\\\"hello java\\\")); // 比较内容：false（区分大小写）\\r\\nSystem.out.println(str.toLowerCase()); // 转小写：\\\"hello java\\\"\\r\\nSystem.out.println(str.split(\\\" \\\")); // 分割字符串：[\\\"Hello\\\", \\\"Java\\\"]\\r\\n注意：String 不可变，每次修改都会创建新对象，频繁修改建议使用StringBuilder（非线程安全）\\r\\n或StringBuffer（线程安全）。\\r\\n4.2 包装类\\r\\n基本类型的包装类用于将基本类型转换为对象，支持装箱（基本类型→对象）和拆箱（对象→基本类\\r\\n型）：\\r\\n基本类型 包装类\\r\\nint Integer\\r\\nchar Character\\r\\ndouble Double\\r\\n示例：\\r\\n// 装箱\\r\\nInteger num1 = 10; // 自动装箱（等价于Integer.valueOf(10)）\\r\\n// 拆箱\\r\\nint num2 = num1; // 自动拆箱（等价于num1.intValue()）\\r\\n// 常用方法\\r\\nSystem.out.println(Integer.parseInt(\\\"123\\\")); // 字符串转int：123\\r\\nSystem.out.println(Integer.MAX_VALUE); // 最大值：2147483647\\r\\n4.3 日期时间类\\r\\nJDK8 + 推荐使用java.time包下的日期时间类（替代旧版Date和Calendar）：\"},{\"id\":44,\"segmentNo\":10,\"pageNo\":10,\"sectionTitle\":\"第10页 · 第1段 · // 获取当前日期\",\"contentText\":\"// 获取当前日期\\r\\nLocalDate today = LocalDate.now();\\r\\nSystem.out.println(today); // 输出：2024-05-20（格式示例）\\r\\n// 获取当前时间\\r\\nLocalTime now = LocalTime.now();\\r\\nSystem.out.println(now); // 输出：14:30:25（格式示例）\\r\\n// 日期计算\\r\\nLocalDate tomorrow = today.plusDays(1);\\r\\nSystem.out.println(tomorrow); // 输出：2024-05-21\\r\\n// 格式化日期\\r\\nDateTimeFormatter formatter = DateTimeFormatter.ofPattern(\\\"yyyy年MM月dd日\\\");\\r\\nString formattedDate = today.format(formatter);\\r\\nSystem.out.println(formattedDate); // 输出：2024年05月20日\\r\\n4.4 集合框架（约 700 字）\\r\\nJava 集合框架（java.util包）用于存储和操作多个对象，分为Collection和Map两大体系：\\r\\n4.4.1 Collection 接口\\r\\nCollection包含List（有序、可重复）、Set（无序、不可重复）、Queue（队列）子接口：\\r\\n4.4.1.1 List 接口\\r\\n常用实现类：ArrayList（数组实现，查询快、增删慢）、LinkedList（链表实现，增删快、查询慢\\r\\n）。\\r\\n示例（ArrayList）：\\r\\nList> list = new ArrayList();\\r\\n// 添加元素\\r\\nlist.add(\\\"苹果\\\");\\r\\nlist.add(\\\"香蕉\\\");\\r\\nlist.add(\\\"橙子\\\");\\r\\n// 插入元素\\r\\nlist.add(1, \\\"葡萄\\\");\\r\\n// 遍历\\r\\nfor (String fruit : list) {\"},{\"id\":45,\"segmentNo\":11,\"pageNo\":10,\"sectionTitle\":\"第10页 · 第2段 ·     System.out.println(fruit); /\",\"contentText\":\"    System.out.println(fruit); // 输出：苹果、葡萄、香蕉、橙子\"},{\"id\":46,\"segmentNo\":12,\"pageNo\":11,\"sectionTitle\":\"第11页 · 第1段 · // 获取元素\",\"contentText\":\"}\\r\\n// 获取元素\\r\\nSystem.out.println(list.get(2)); // 输出：香蕉\\r\\n// 删除元素\\r\\nlist.remove(3);\\r\\n// 查找元素索引\\r\\nSystem.out.println(list.indexOf(\\\"香蕉\\\")); // 输出：2\\r\\n4.4.1.2 Set 接口\\r\\n常用实现类：HashSet（哈希表实现，无序）、TreeSet（红黑树实现，自然排序）。\\r\\n示例（HashSet）：\\r\\nSet = new HashSetset.add(\\\"张三\\\");\\r\\nset.add(\\\"李四\\\");\\r\\nset.add(\\\"张三\\\"); // 重复元素，添加失败\\r\\nSystem.out.println(set.size()); // 输出：2\\r\\n// 遍历\\r\\nIterator<String> iterator = set.iterator();\\r\\nwhile (iterator.hasNext()) {\\r\\n    System.out.println(iterator.next()); // 无序输出：张三、李四\\r\\n}\\r\\n4.4.2 Map 接口\\r\\nMap存储键值对（key-value），key 唯一，value 可重复，常用实现类：HashMap（哈希表实现，无序\\r\\n）、TreeMap（红黑树实现，按键排序）。\\r\\n示例（HashMap）：\\r\\nMap Integer> map = new HashMap<>();\\r\\n// 添加键值对\\r\\nmap.put(\\\"语文\\\", 90);\\r\\nmap.put(\\\"数学\\\", 95);\\r\\nmap.put(\\\"英语\\\", 88);\\r\\n// 获取value\\r\\nSystem.out.println(map.get(\\\"数学\\\")); // 输出：95\\r\\n// 遍历key\"},{\"id\":47,\"segmentNo\":13,\"pageNo\":12,\"sectionTitle\":\"第12页 · 第1段 · // 遍历键值对\",\"contentText\":\"for (String subject : map.keySet()) {\\r\\n    System.out.println(subject + \\\":\\\" + map.get(subject));\\r\\n}\\r\\n// 遍历键值对\\r\\nfor (Map.Entry : map.entrySet()) {\\r\\n    System.out.println(entry.getKey() + \\\":\\\" + entry.getValue());\\r\\n}\\r\\n// 判断key是否存在\\r\\nSystem.out.println(map.containsKey(\\\"物理\\\")); // 输出：false\\r\\n五、异常处理（约 400 字）\\r\\n5.1 异常概念\\r\\n异常是程序运行时出现的错误（如空指针、数组越界），Java 通过异常处理机制避免程序崩溃，核心\\r\\n类为Throwable，其下分为Error（严重错误，无法处理）和Exception（可处理异常）。\\r\\n5.2 异常处理方式\\r\\n5.2.1 try-catch-finally\\r\\ntry {\\r\\n    // 可能出现异常的代码\\r\\n    int[] arr = {1, 2, 3};\\r\\n    System.out.println(arr[3]); // 数组越界异常\\r\\n} catch (ArrayIndexOutOfBoundsException e) {\\r\\n    // 捕获指定异常并处理\\r\\n    System.out.println(\\\"异常信息：\\\" + e.getMessage()); // 输出：3\\r\\n} finally {\\r\\n    // 无论是否异常，都会执行（常用于资源释放）\\r\\n    System.out.println(\\\"程序执行完毕\\\");\\r\\n}\\r\\n5.2.2 throws 声明异常\"},{\"id\":48,\"segmentNo\":14,\"pageNo\":13,\"sectionTitle\":\"第13页 · 第1段 ·     fr.close();\",\"contentText\":\"方法抛出异常，由调用者处理：\\r\\npublic static void readFile() throws IOException {\\r\\n    FileReader fr = new FileReader(\\\"test.txt\\\");\\r\\n    fr.close();\\r\\n}\\r\\n// 调用者处理异常\\r\\npublic static void main(String[] args) {\\r\\n    try {\\r\\n        readFile();\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    }\\r\\n}\\r\\n5.2.3 自定义异常\\r\\n继承Exception或RuntimeException实现自定义异常：\\r\\n// 自定义异常类\\r\\nclass AgeException extends Exception {\\r\\n    public AgeException(String message) {\\r\\n        super(message);\\r\\n    }\\r\\n}\\r\\n// 使用自定义异常\\r\\npublic static void checkAge(int age) throws AgeException {\\r\\n    if (age  > 120) {\\r\\n        throw new AgeException(\\\"年龄无效：\\\" + age);\\r\\n    }\\r\\n}\\r\\n六、IO 流（约 500 字）\\r\\nIO 流用于文件读写、数据传输，按流向分为输入流（InputStream/Reader）和输出流（-\\r\\nOutputStream/Writer），按处理单位分为字节流（处理二进制文件）和字符流（处理文本文件）。\"},{\"id\":49,\"segmentNo\":15,\"pageNo\":14,\"sectionTitle\":\"第14页 · 第1段 · 6.1 字节流示例（复制图片）\",\"contentText\":\"6.1 字节流示例（复制图片）\\r\\npublic static void copyImage() {\\r\\n    FileInputStream fis = null;\\r\\n    FileOutputStream fos = null;\\r\\n    try {\\r\\n        // 输入流（读取源文件）\\r\\n        fis = new FileInputStream(\\\"source.jpg\\\");\\r\\n        // 输出流（写入目标文件）\\r\\n        fos = new FileOutputStream(\\\"target.jpg\\\");\\r\\n        byte[] buffer = new byte[1024]; // 缓冲区\\r\\n        int len;\\r\\n        // 读取数据并写入\\r\\n        while ((len = fis.read(buffer)) != -1) {\\r\\n            fos.write(buffer, 0, len);\\r\\n        }\\r\\n        System.out.println(\\\"图片复制成功\\\");\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    } finally {\\r\\n        // 关闭流（释放资源）\\r\\n        try {\\r\\n            if (fis != null) fis.close();\\r\\n            if (fos != null) fos.close();\\r\\n        } catch (IOException e) {\\r\\n            e.printStackTrace();\\r\\n        }\\r\\n    }\\r\\n}\\r\\n6.2 字符流示例（读写文本文件）\\r\\npublic static void readTextFile() {\\r\\n    FileReader fr = null;\"},{\"id\":50,\"segmentNo\":16,\"pageNo\":14,\"sectionTitle\":\"第14页 · 第2段 ·     try {\",\"contentText\":\"    BufferedReader br = null; // 缓冲字符流，提高效率\\r\\n    try {\\r\\n        fr = new FileReader(\\\"test.txt\\\");\\r\\n        br = new BufferedReader(fr);\"},{\"id\":51,\"segmentNo\":17,\"pageNo\":15,\"sectionTitle\":\"第15页 · 第1段 ·         // 按行读取文本\",\"contentText\":\"        String line;\\r\\n        // 按行读取文本\\r\\n        while ((line = br.readLine()) != null) {\\r\\n            System.out.println(line);\\r\\n        }\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    } finally {\\r\\n        try {\\r\\n            if (br != null) br.close();\\r\\n            if (fr != null) fr.close();\\r\\n        } catch (IOException e) {\\r\\n            e.printStackTrace();\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 写入文本文件\\r\\npublic static void writeTextFile() {\\r\\n    FileWriter fw = null;\\r\\n    BufferedWriter bw = null;\\r\\n    try {\\r\\n        // true表示追加写入，默认覆盖\\r\\n        fw = new FileWriter(\\\"test.txt\\\", true);\\r\\n        bw = new BufferedWriter(fw);\\r\\n        bw.write(\\\"Hello Java\\\");\\r\\n        bw.newLine(); // 换行\\r\\n        System.out.println(\\\"写入成功\\\");\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    } finally {\\r\\n        try {\\r\\n            if (bw != null) bw.close();\"},{\"id\":52,\"segmentNo\":18,\"pageNo\":15,\"sectionTitle\":\"第15页 · 第2段 ·         }\",\"contentText\":\"            if (fw != null) fw.close();\\r\\n        } catch (IOException e) {\\r\\n            e.printStackTrace();\\r\\n        }\\r\\n    }\\r\\n}\"},{\"id\":53,\"segmentNo\":19,\"pageNo\":16,\"sectionTitle\":\"第16页 · 第1段 · 七、多线程（约 600 字）\",\"contentText\":\"七、多线程（约 600 字）\\r\\n7.1 线程概念\\r\\n线程是程序执行的最小单位，一个进程可包含多个线程，多线程可并发执行，提高程序效率。\\r\\n7.2 线程创建方式\\r\\n7.2.1 继承 Thread 类\\r\\nclass MyThread extends Thread {\\r\\n    @Override\\r\\n    public void run() {\\r\\n        // 线程执行逻辑\\r\\n        for (int i = 0; i < 10; i++) {\\r\\n            System.out.println(Thread.currentThread().getName() + \\\":\\\" + i);\\r\\n            try {\\r\\n                Thread.sleep(100); // 线程休眠100毫秒\\r\\n            } catch (InterruptedException e) {\\r\\n                e.printStackTrace();\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        MyThread thread1 = new MyThread();\\r\\n        MyThread thread2 = new MyThread();\\r\\n        thread1.setName(\\\"线程1\\\");\\r\\n        thread2.setName(\\\"线程2\\\");\\r\\n        thread1.start(); // 启动线程（调用run方法）\\r\\n        thread2.start();\\r\\n    }\\r\\n}\"},{\"id\":54,\"segmentNo\":20,\"pageNo\":17,\"sectionTitle\":\"第17页 · 第1段 · 7.2.2 实现 Runnable 接口\",\"contentText\":\"7.2.2 实现 Runnable 接口\\r\\nclass MyRunnable implements Runnable {\\r\\n    @Override\\r\\n    public void run() {\\r\\n        for (int i = 0; i  i++) {\\r\\n            System.out.println(Thread.currentThread().getName() + \\\":\\\" + i);\\r\\n            try {\\r\\n                Thread.sleep(100);\\r\\n            } catch (InterruptedException e) {\\r\\n                e.printStackTrace();\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Thread thread1 = new Thread(new MyRunnable(), \\\"线程1\\\");\\r\\n        Thread thread2 = new Thread(new MyRunnable(), \\\"线程2\\\");\\r\\n        thread1.start();\\r\\n        thread2.start();\\r\\n    }\\r\\n}\\r\\n7.2.3 实现 Callable 接口（带返回值）\\r\\nclass MyCallable implements Callable\\r\\n    @Override\\r\\n    public Integer call() throws Exception {\\r\\n        int sum = 0;\\r\\n        for (int i = 1; i 0; i++) {\\r\\n            sum += i;\\r\\n        }\\r\\n        return sum; // 返回结果\"},{\"id\":55,\"segmentNo\":21,\"pageNo\":17,\"sectionTitle\":\"第17页 · 第2段 ·     }\",\"contentText\":\"    }\\r\\n}\\r\\n// 测试\"},{\"id\":56,\"segmentNo\":22,\"pageNo\":18,\"sectionTitle\":\"第18页 · 第1段 · public class Test {\",\"contentText\":\"public class Test {\\r\\n    public static void main(String[] args) throws ExecutionException, InterruptedException {\\r\\n        Callable = new MyCallable();\\r\\n        FutureTaskTask = new FutureTaskcallable);\\r\\n        new Thread(futureTask).start();\\r\\n        Integer result = futureTask.get(); // 获取返回值（阻塞等待）\\r\\n        System.out.println(\\\"1-100求和：\\\" + result); // 输出：5050\\r\\n    }\\r\\n}\\r\\n7.3 线程状态与控制\\r\\n线程生命周期包括：新建（New）、就绪（Runnable）、运行（Running）、阻塞（Blocked）、死\\r\\n亡（Terminated）。\\r\\n常用线程控制方法：\\r\\n◦ start()：启动线程，进入就绪状态；\\r\\n◦ run()：线程执行逻辑；\\r\\n◦ sleep(long ms)：线程休眠，进入阻塞状态；\\r\\n◦ join()：等待线程执行完毕；\\r\\n◦ synchronized：同步锁，解决线程安全问题。\\r\\n线程安全示例（同步代码块）：\\r\\nclass TicketSale implements Runnable {\\r\\n    private int ticket = 100;\\r\\n    private Object lock = new Object(); // 锁对象\\r\\n    @Override\\r\\n    public void run() {\\r\\n        while (true) {\\r\\n            synchronized (lock) { // 同步代码块，保证原子性\\r\\n                if (ticket > 0) {\"},{\"id\":57,\"segmentNo\":23,\"pageNo\":18,\"sectionTitle\":\"第18页 · 第2段 ·                     System.out.p\",\"contentText\":\"                    System.out.println(Thread.currentThread().getName() + \\\"售出第\\\" + ticket + \\\"张票\\\");\\r\\n                    ticket--;\\r\\n                    try {\\r\\n                        Thread.sleep(50);\\r\\n                    } catch (InterruptedException e) {\\r\\n                        e.printStackTrace();\"},{\"id\":58,\"segmentNo\":24,\"pageNo\":19,\"sectionTitle\":\"第19页 · 第1段 ·                 }\",\"contentText\":\"                    }\\r\\n                } else {\\r\\n                    break;\\r\\n                }\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n八、注解与反射（约 300 字）\\r\\n8.1 注解\\r\\n注解（Annotation）用于修饰类、方法、变量，提供元数据信息，常用内置注解：\\r\\n◦ @Override：标识方法重写；\\r\\n◦ @Deprecated：标识方法已过时；\\r\\n◦ @SuppressWarnings：抑制编译器警告。\\r\\n自定义注解示例：\\r\\n// 定义注解\\r\\n@Retention(RetentionPolicy.RUNTIME) // 注解保留到运行时\\r\\n@Target(ElementType.METHOD) // 注解作用于方法\\r\\npublic @interface MyAnnotation {\\r\\n    String value() default \\\"\\\"; // 注解属性\\r\\n}\\r\\n// 使用注解\\r\\npublic class Test {\\r\\n    @MyAnnotation(\\\"测试方法\\\")\\r\\n    public void test() {\\r\\n        System.out.println(\\\"注解测试\\\");\\r\\n    }\\r\\n}\\r\\n8.2 反射\"},{\"id\":59,\"segmentNo\":25,\"pageNo\":20,\"sectionTitle\":\"第20页 · 第1段 · 为Class。\",\"contentText\":\"反射（Reflection）允许程序在运行时获取类的信息（属性、方法、构造器）并操作，核心类\\r\\n为Class。\\r\\n示例（通过反射调用方法）：\\r\\npublic class Test {\\r\\n    public void sayHello(String name) {\\r\\n        System.out.println(\\\"Hello \\\" + name);\\r\\n    }\\r\\n    public static void main(String[] args) throws Exception {\\r\\n        // 获取Class对象\\r\\n        Class;\\r\\n        // 创建对象\\r\\n        Object obj = clazz.newInstance();\\r\\n        // 获取方法（参数：方法名、参数类型）\\r\\n        Method method = clazz.getMethod(\\\"sayHello\\\", String.class);\\r\\n        // 调用方法（参数：对象、方法参数）\\r\\n        method.invoke(obj, \\\"Java\\\"); // 输出：Hello Java\\r\\n    }\\r\\n}\\r\\n九、Java 框架简介（约 200 字）\\r\\nJava 主流框架用于简化企业级开发：\\r\\n◦ Spring：核心是 IoC（控制反转）和 AOP（面向切面编程），提供依赖注入、事务管理等功能，是企\\r\\n业级开发的基石；\\r\\n◦ Spring Boot：基于 Spring，简化配置，实现 “开箱即用”，降低框架使用门槛；\\r\\n◦ MyBatis：持久层框架，简化 JDBC 操作，通过 XML 或注解映射数据库操作；\\r\\n◦ Spring MVC：Web 层框架，实现 MVC 设计模式，处理请求和响应；\\r\\n◦ Spring Cloud：微服务架构框架，提供服务注册发现、负载均衡、熔断等功能。\\r\\n这些框架相互配合，形成了 Java EE 开发的主流技术栈（SSM：Spring+Spring MVC+MyBatis，\"},{\"id\":60,\"segmentNo\":26,\"pageNo\":20,\"sectionTitle\":\"第20页 · 第2段 · Spring Boot+Spring Cloud）。\",\"contentText\":\"Spring Boot+Spring Cloud）。\\r\\n（注：文档部分内容可能由 AI 生成）\"}]}','SUCCESS',NULL,'2026-04-20 14:19:24','2026-04-20 14:19:24','2026-04-20 14:19:38','2026-04-20 14:19:38'),(58,18,125,'material.detail','{\"materialId\":7}','{\"id\":7,\"title\":\"Java核心知识全面梳理\",\"materialType\":\"PDF\",\"sourceType\":\"UPLOAD\",\"fileName\":\"Java核心知识全面梳理.pdf\",\"fileUrl\":\"C:\\\\Users\\\\雪\\\\Desktop\\\\AI-Intelligent-Learning-Assistant-System\\\\backend\\\\uploads\\\\cb6c96d4-a5bf-4e78-ac4e-5192b399b19a.pdf\",\"fileSize\":221847,\"parseStatus\":\"SUCCESS\",\"summaryStatus\":\"SUCCESS\",\"difficultyLevel\":3,\"tags\":null,\"totalPages\":20,\"totalCharacters\":15837,\"embeddingStatus\":\"SUCCESS\",\"embeddedSegmentCount\":26,\"totalSegmentCount\":26,\"lastStudyTime\":null,\"createdAt\":\"2026-04-17T19:07:24\",\"segments\":[{\"id\":35,\"segmentNo\":1,\"pageNo\":1,\"sectionTitle\":\"第1页 · 第1段 · Java 核心知识全面梳理\",\"contentText\":\"Java 核心知识全面梳理\\r\\n一、Java 语言概述（约 500 字）\\r\\n1.1 语言简介\\r\\nJava 是由 Sun Microsystems（后被 Oracle 收购）于 1995 年推出的面向对象编程语言，其设计理念是\\r\\n “一次编写，到处运行（Write Once, Run Anywhere, WORA）”。核心优势在于跨平台性，通过 Java\\r\\n 虚拟机（JVM）实现 ——Java 源代码编译为字节码（.class 文件），再由不同平台的 JVM 解释执行，\\r\\n无需修改代码即可在 Windows、Linux、macOS 等系统运行。\\r\\n1.2 主要特点\\r\\n◦ 面向对象：封装、继承、多态三大特性，符合现实世界建模逻辑；\\r\\n◦ 跨平台：依赖 JVM 屏蔽底层系统差异，字节码具备平台无关性；\\r\\n◦ 安全性：内置安全机制，避免指针直接操作，防止内存泄露和恶意攻击；\\r\\n◦ 健壮性：强类型检查、异常处理机制，提升程序稳定性；\\r\\n◦ 多线程：原生支持多线程编程，适合并发场景开发。\\r\\n1.3 应用场景\\r\\nJava 广泛应用于企业级开发（Spring、MyBatis 框架）、移动开发（Android 应用）、大数据处理（-\\r\\nHadoop 生态）、中间件开发（Tomcat、Nacos）等领域，是当前最主流的编程语言之一。\\r\\n二、Java 基础语法（约 800 字）\\r\\n2.1 数据类型\\r\\nJava 数据类型分为基本类型和引用类型，其中基本类型共 8 种：\\r\\n类型 占用空间 取值范围\"},{\"id\":36,\"segmentNo\":2,\"pageNo\":2,\"sectionTitle\":\"第2页 · 第1段 · byte 1 字节 -128 ~ 127\",\"contentText\":\"byte 1 字节 -128 ~ 127\\r\\nshort 2 字节 -32768 ~ 32767\\r\\nint 4 字节 -2³¹ ~ 2³¹-1\\r\\nlong 8 字节 -2v³ ~ 2v³-1\\r\\nfloat 4 字节 单精度浮点数，约 ±3.4e38\\r\\ndouble 8 字节 双精度浮点数，约 ±1.8e308\\r\\nchar 2 字节 Unicode 字符（0 ~ 65535）\\r\\nboolean 1 字节 true/false\\r\\n引用类型包括类、接口、数组、枚举等，本质是指向对象的内存地址。\\r\\n2.2 变量与常量\\r\\n◦ 变量：需声明数据类型，语法为类型 变量名 = 初始值;，如int age = 20;；\\r\\n◦ 常量：用final修饰，一旦赋值不可修改，语法为final 类型 常量名 = 值;，如final double PI = 3.\\r\\n14159;（常量名通常大写）。\\r\\n2.3 运算符\\r\\n◦ 算术运算符：+\\u0001-\\u0001*\\u0001/\\u0001%\\u0001++\\u0001--（注意++前置自增与后置自增的区别）；\\r\\n◦ 关系运算符：`==、!=、>、<、>=、返回 boolean 类型；\\r\\n◦ 逻辑运算符：&&（短路与）、||（短路或）、!（非）；\\r\\n◦ 赋值运算符：=\\u0001+=\\u0001-=\\u0001*=\\u0001/=等；\\r\\n◦ 三元运算符：条件表达式 ? 表达式1 : 表达式2，如int max = a > b ? a : b;。\\r\\n2.4 流程控制\\r\\n2.4.1 条件语句\"},{\"id\":37,\"segmentNo\":3,\"pageNo\":3,\"sectionTitle\":\"第3页 · 第1段 · // if-else语句\",\"contentText\":\"// if-else语句\\r\\nif (age >= 18) {\\r\\n    System.out.println(\\\"成年人\\\");\\r\\n} else if (age >= 6) {\\r\\n    System.out.println(\\\"青少年\\\");\\r\\n} else {\\r\\n    System.out.println(\\\"儿童\\\");\\r\\n}\\r\\n// switch语句（JDK7+支持String类型）\\r\\nswitch (season) {\\r\\n    case \\\"春季\\\":\\r\\n        System.out.println(\\\"3-5月\\\");\\r\\n        break;\\r\\n    case \\\"夏季\\\":\\r\\n        System.out.println(\\\"6-8月\\\");\\r\\n        break;\\r\\n    default:\\r\\n        System.out.println(\\\"未知季节\\\");\\r\\n}\\r\\n2.4.2 循环语句\\r\\n// for循环\\r\\nfor (int i = 0; i  i++) {\\r\\n    System.out.println(i); // 输出0-9\\r\\n}\\r\\n// while循环\\r\\nint j = 0;\\r\\nwhile (j 0) {\\r\\n    System.out.println(j);\\r\\n    j++;\\r\\n}\\r\\n// do-while循环（至少执行一次）\\r\\nint k = 0;\\r\\ndo {\\r\\n    System.out.println(k);\\r\\n    k++;\\r\\n} while (k < 10);\"},{\"id\":38,\"segmentNo\":4,\"pageNo\":4,\"sectionTitle\":\"第4页 · 第1段 · 2.5 数组\",\"contentText\":\"2.5 数组\\r\\n数组是存储同一类型数据的固定长度容器，声明与初始化方式：\\r\\n// 声明并初始化\\r\\nint[] arr1 = {1, 2, 3};\\r\\n// 指定长度初始化\\r\\nint[] arr2 = new int[3];\\r\\narr2[0] = 1;\\r\\narr2[1] = 2;\\r\\narr2[2] = 3;\\r\\n// 遍历数组（增强for循环）\\r\\nfor (int num : arr1) {\\r\\n    System.out.println(num);\\r\\n}\\r\\n三、面向对象编程（约 1000 字）\\r\\n3.1 核心概念\\r\\n面向对象编程（OOP）以 “对象” 为核心，将数据和行为封装为一个整体，通过继承和多态实现代码\\r\\n复用和扩展。\\r\\n3.2 类与对象\\r\\n◦ 类：对象的模板，定义对象的属性（成员变量）和行为（成员方法）；\\r\\n◦ 对象：类的实例化结果，通过new关键字创建。\\r\\n示例代码：\\r\\n// 定义Person类\\r\\nclass Person {\\r\\n    // 成员变量（属性）\\r\\n    String name;\\r\\n    int age;\\r\\n    // 成员方法（行为）\"},{\"id\":39,\"segmentNo\":5,\"pageNo\":5,\"sectionTitle\":\"第5页 · 第1段 ·     }\",\"contentText\":\"    public void eat() {\\r\\n        System.out.println(name + \\\"正在吃饭\\\");\\r\\n    }\\r\\n    public void sleep() {\\r\\n        System.out.println(name + \\\"正在睡觉\\\");\\r\\n    }\\r\\n}\\r\\n// 创建对象并使用\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Person person = new Person();\\r\\n        person.name = \\\"张三\\\";\\r\\n        person.age = 25;\\r\\n        person.eat(); // 输出：张三正在吃饭\\r\\n        person.sleep(); // 输出：张三正在睡觉\\r\\n    }\\r\\n}\\r\\n3.3 封装\\r\\n封装是将对象的属性私有化，通过公共的getter/setter方法控制访问，隐藏内部实现细节，提升安\\r\\n全性。\\r\\n示例代码：\\r\\nclass Person {\\r\\n    // 私有成员变量（仅本类可访问）\\r\\n    private String name;\\r\\n    private int age;\\r\\n    // getter方法（获取属性值）\\r\\n    public String getName() {\\r\\n        return name;\\r\\n    }\\r\\n    // setter方法（设置属性值，可添加逻辑校验）\\r\\n    public void setName(String name) {\\r\\n        if (name != null && !name.isEmpty()) {\\r\\n            this.name = name;\\r\\n        } else {\\r\\n            System.out.println(\\\"姓名不能为空\\\");\\r\\n        }\"},{\"id\":40,\"segmentNo\":6,\"pageNo\":6,\"sectionTitle\":\"第6页 · 第1段 ·     }\",\"contentText\":\"    }\\r\\n    public int getAge() {\\r\\n        return age;\\r\\n    }\\r\\n    public void setAge(int age) {\\r\\n        if (age >= 0 && age  120) {\\r\\n            this.age = age;\\r\\n        } else {\\r\\n            System.out.println(\\\"年龄无效\\\");\\r\\n        }\\r\\n    }\\r\\n}\\r\\n3.4 继承\\r\\n继承允许子类继承父类的属性和方法，子类可扩展新功能或重写父类方法，关键字为extends。Java \\r\\n支持单继承（一个子类只能有一个父类），但可通过接口实现多继承效果。\\r\\n示例代码：\\r\\n// 父类\\r\\nclass Animal {\\r\\n    public void move() {\\r\\n        System.out.println(\\\"动物会移动\\\");\\r\\n    }\\r\\n}\\r\\n// 子类继承父类\\r\\nclass Dog extends Animal {\\r\\n    // 重写父类方法\\r\\n    @Override\\r\\n    public void move() {\\r\\n        System.out.println(\\\"狗会跑\\\");\\r\\n    }\\r\\n    // 子类扩展方法\\r\\n    public void bark() {\\r\\n        System.out.println(\\\"狗会叫\\\");\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\"},{\"id\":41,\"segmentNo\":7,\"pageNo\":7,\"sectionTitle\":\"第7页 · 第1段 ·     public static void main(Stri\",\"contentText\":\"    public static void main(String[] args) {\\r\\n        Dog dog = new Dog();\\r\\n        dog.move(); // 输出：狗会跑（重写后）\\r\\n        dog.bark(); // 输出：狗会叫（扩展方法）\\r\\n    }\\r\\n}\\r\\n3.5 多态\\r\\n多态是指同一行为在不同对象上表现出不同形态，实现条件：\\r\\n1. 子类继承父类；\\r\\n2. 子类重写父类方法；\\r\\n3. 父类引用指向子类对象。\\r\\n示例代码：\\r\\nclass Animal {\\r\\n    public void sound() {\\r\\n        System.out.println(\\\"动物发出声音\\\");\\r\\n    }\\r\\n}\\r\\nclass Cat extends Animal {\\r\\n    @Override\\r\\n    public void sound() {\\r\\n        System.out.println(\\\"猫喵喵叫\\\");\\r\\n    }\\r\\n}\\r\\nclass Bird extends Animal {\\r\\n    @Override\\r\\n    public void sound() {\\r\\n        System.out.println(\\\"鸟叽叽叫\\\");\\r\\n    }\\r\\n}\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Animal animal1 = new Cat();\\r\\n        Animal animal2 = new Bird();\\r\\n        animal1.sound(); // 输出：猫喵喵叫\"},{\"id\":42,\"segmentNo\":8,\"pageNo\":8,\"sectionTitle\":\"第8页 · 第1段 ·     }\",\"contentText\":\"        animal2.sound(); // 输出：鸟叽叽叫\\r\\n    }\\r\\n}\\r\\n3.6 接口与抽象类\\r\\n◦ 抽象类：用abstract修饰，包含抽象方法（无实现）和普通方法，不能实例化，需子类继承并实现抽\\r\\n象方法；\\r\\n◦ 接口：用interface修饰，仅包含抽象方法（JDK8 + 支持默认方法和静态方法），类通过-\\r\\nimplements实现接口，可多实现。\\r\\n示例（接口）：\\r\\ninterface Flyable {\\r\\n    void fly(); // 抽象方法\\r\\n}\\r\\nclass Bird implements Flyable {\\r\\n    @Override\\r\\n    public void fly() {\\r\\n        System.out.println(\\\"鸟展翅飞翔\\\");\\r\\n    }\\r\\n}\\r\\nclass Plane implements Flyable {\\r\\n    @Override\\r\\n    public void fly() {\\r\\n        System.out.println(\\\"飞机引擎驱动飞行\\\");\\r\\n    }\\r\\n}\\r\\n四、Java 核心类库（约 600 字）\\r\\n4.1 String 类\\r\\nString 是不可变字符序列，常用方法：\"},{\"id\":43,\"segmentNo\":9,\"pageNo\":9,\"sectionTitle\":\"第9页 · 第1段 · String str = \\\"Hello Java\\\";\",\"contentText\":\"String str = \\\"Hello Java\\\";\\r\\nSystem.out.println(str.length()); // 长度：9\\r\\nSystem.out.println(str.charAt(0)); // 获取索引0字符：\'H\'\\r\\nSystem.out.println(str.substring(6)); // 截取子串：\\\"Java\\\"\\r\\nSystem.out.println(str.equals(\\\"hello java\\\")); // 比较内容：false（区分大小写）\\r\\nSystem.out.println(str.toLowerCase()); // 转小写：\\\"hello java\\\"\\r\\nSystem.out.println(str.split(\\\" \\\")); // 分割字符串：[\\\"Hello\\\", \\\"Java\\\"]\\r\\n注意：String 不可变，每次修改都会创建新对象，频繁修改建议使用StringBuilder（非线程安全）\\r\\n或StringBuffer（线程安全）。\\r\\n4.2 包装类\\r\\n基本类型的包装类用于将基本类型转换为对象，支持装箱（基本类型→对象）和拆箱（对象→基本类\\r\\n型）：\\r\\n基本类型 包装类\\r\\nint Integer\\r\\nchar Character\\r\\ndouble Double\\r\\n示例：\\r\\n// 装箱\\r\\nInteger num1 = 10; // 自动装箱（等价于Integer.valueOf(10)）\\r\\n// 拆箱\\r\\nint num2 = num1; // 自动拆箱（等价于num1.intValue()）\\r\\n// 常用方法\\r\\nSystem.out.println(Integer.parseInt(\\\"123\\\")); // 字符串转int：123\\r\\nSystem.out.println(Integer.MAX_VALUE); // 最大值：2147483647\\r\\n4.3 日期时间类\\r\\nJDK8 + 推荐使用java.time包下的日期时间类（替代旧版Date和Calendar）：\"},{\"id\":44,\"segmentNo\":10,\"pageNo\":10,\"sectionTitle\":\"第10页 · 第1段 · // 获取当前日期\",\"contentText\":\"// 获取当前日期\\r\\nLocalDate today = LocalDate.now();\\r\\nSystem.out.println(today); // 输出：2024-05-20（格式示例）\\r\\n// 获取当前时间\\r\\nLocalTime now = LocalTime.now();\\r\\nSystem.out.println(now); // 输出：14:30:25（格式示例）\\r\\n// 日期计算\\r\\nLocalDate tomorrow = today.plusDays(1);\\r\\nSystem.out.println(tomorrow); // 输出：2024-05-21\\r\\n// 格式化日期\\r\\nDateTimeFormatter formatter = DateTimeFormatter.ofPattern(\\\"yyyy年MM月dd日\\\");\\r\\nString formattedDate = today.format(formatter);\\r\\nSystem.out.println(formattedDate); // 输出：2024年05月20日\\r\\n4.4 集合框架（约 700 字）\\r\\nJava 集合框架（java.util包）用于存储和操作多个对象，分为Collection和Map两大体系：\\r\\n4.4.1 Collection 接口\\r\\nCollection包含List（有序、可重复）、Set（无序、不可重复）、Queue（队列）子接口：\\r\\n4.4.1.1 List 接口\\r\\n常用实现类：ArrayList（数组实现，查询快、增删慢）、LinkedList（链表实现，增删快、查询慢\\r\\n）。\\r\\n示例（ArrayList）：\\r\\nList> list = new ArrayList();\\r\\n// 添加元素\\r\\nlist.add(\\\"苹果\\\");\\r\\nlist.add(\\\"香蕉\\\");\\r\\nlist.add(\\\"橙子\\\");\\r\\n// 插入元素\\r\\nlist.add(1, \\\"葡萄\\\");\\r\\n// 遍历\\r\\nfor (String fruit : list) {\"},{\"id\":45,\"segmentNo\":11,\"pageNo\":10,\"sectionTitle\":\"第10页 · 第2段 ·     System.out.println(fruit); /\",\"contentText\":\"    System.out.println(fruit); // 输出：苹果、葡萄、香蕉、橙子\"},{\"id\":46,\"segmentNo\":12,\"pageNo\":11,\"sectionTitle\":\"第11页 · 第1段 · // 获取元素\",\"contentText\":\"}\\r\\n// 获取元素\\r\\nSystem.out.println(list.get(2)); // 输出：香蕉\\r\\n// 删除元素\\r\\nlist.remove(3);\\r\\n// 查找元素索引\\r\\nSystem.out.println(list.indexOf(\\\"香蕉\\\")); // 输出：2\\r\\n4.4.1.2 Set 接口\\r\\n常用实现类：HashSet（哈希表实现，无序）、TreeSet（红黑树实现，自然排序）。\\r\\n示例（HashSet）：\\r\\nSet = new HashSetset.add(\\\"张三\\\");\\r\\nset.add(\\\"李四\\\");\\r\\nset.add(\\\"张三\\\"); // 重复元素，添加失败\\r\\nSystem.out.println(set.size()); // 输出：2\\r\\n// 遍历\\r\\nIterator<String> iterator = set.iterator();\\r\\nwhile (iterator.hasNext()) {\\r\\n    System.out.println(iterator.next()); // 无序输出：张三、李四\\r\\n}\\r\\n4.4.2 Map 接口\\r\\nMap存储键值对（key-value），key 唯一，value 可重复，常用实现类：HashMap（哈希表实现，无序\\r\\n）、TreeMap（红黑树实现，按键排序）。\\r\\n示例（HashMap）：\\r\\nMap Integer> map = new HashMap<>();\\r\\n// 添加键值对\\r\\nmap.put(\\\"语文\\\", 90);\\r\\nmap.put(\\\"数学\\\", 95);\\r\\nmap.put(\\\"英语\\\", 88);\\r\\n// 获取value\\r\\nSystem.out.println(map.get(\\\"数学\\\")); // 输出：95\\r\\n// 遍历key\"},{\"id\":47,\"segmentNo\":13,\"pageNo\":12,\"sectionTitle\":\"第12页 · 第1段 · // 遍历键值对\",\"contentText\":\"for (String subject : map.keySet()) {\\r\\n    System.out.println(subject + \\\":\\\" + map.get(subject));\\r\\n}\\r\\n// 遍历键值对\\r\\nfor (Map.Entry : map.entrySet()) {\\r\\n    System.out.println(entry.getKey() + \\\":\\\" + entry.getValue());\\r\\n}\\r\\n// 判断key是否存在\\r\\nSystem.out.println(map.containsKey(\\\"物理\\\")); // 输出：false\\r\\n五、异常处理（约 400 字）\\r\\n5.1 异常概念\\r\\n异常是程序运行时出现的错误（如空指针、数组越界），Java 通过异常处理机制避免程序崩溃，核心\\r\\n类为Throwable，其下分为Error（严重错误，无法处理）和Exception（可处理异常）。\\r\\n5.2 异常处理方式\\r\\n5.2.1 try-catch-finally\\r\\ntry {\\r\\n    // 可能出现异常的代码\\r\\n    int[] arr = {1, 2, 3};\\r\\n    System.out.println(arr[3]); // 数组越界异常\\r\\n} catch (ArrayIndexOutOfBoundsException e) {\\r\\n    // 捕获指定异常并处理\\r\\n    System.out.println(\\\"异常信息：\\\" + e.getMessage()); // 输出：3\\r\\n} finally {\\r\\n    // 无论是否异常，都会执行（常用于资源释放）\\r\\n    System.out.println(\\\"程序执行完毕\\\");\\r\\n}\\r\\n5.2.2 throws 声明异常\"},{\"id\":48,\"segmentNo\":14,\"pageNo\":13,\"sectionTitle\":\"第13页 · 第1段 ·     fr.close();\",\"contentText\":\"方法抛出异常，由调用者处理：\\r\\npublic static void readFile() throws IOException {\\r\\n    FileReader fr = new FileReader(\\\"test.txt\\\");\\r\\n    fr.close();\\r\\n}\\r\\n// 调用者处理异常\\r\\npublic static void main(String[] args) {\\r\\n    try {\\r\\n        readFile();\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    }\\r\\n}\\r\\n5.2.3 自定义异常\\r\\n继承Exception或RuntimeException实现自定义异常：\\r\\n// 自定义异常类\\r\\nclass AgeException extends Exception {\\r\\n    public AgeException(String message) {\\r\\n        super(message);\\r\\n    }\\r\\n}\\r\\n// 使用自定义异常\\r\\npublic static void checkAge(int age) throws AgeException {\\r\\n    if (age  > 120) {\\r\\n        throw new AgeException(\\\"年龄无效：\\\" + age);\\r\\n    }\\r\\n}\\r\\n六、IO 流（约 500 字）\\r\\nIO 流用于文件读写、数据传输，按流向分为输入流（InputStream/Reader）和输出流（-\\r\\nOutputStream/Writer），按处理单位分为字节流（处理二进制文件）和字符流（处理文本文件）。\"},{\"id\":49,\"segmentNo\":15,\"pageNo\":14,\"sectionTitle\":\"第14页 · 第1段 · 6.1 字节流示例（复制图片）\",\"contentText\":\"6.1 字节流示例（复制图片）\\r\\npublic static void copyImage() {\\r\\n    FileInputStream fis = null;\\r\\n    FileOutputStream fos = null;\\r\\n    try {\\r\\n        // 输入流（读取源文件）\\r\\n        fis = new FileInputStream(\\\"source.jpg\\\");\\r\\n        // 输出流（写入目标文件）\\r\\n        fos = new FileOutputStream(\\\"target.jpg\\\");\\r\\n        byte[] buffer = new byte[1024]; // 缓冲区\\r\\n        int len;\\r\\n        // 读取数据并写入\\r\\n        while ((len = fis.read(buffer)) != -1) {\\r\\n            fos.write(buffer, 0, len);\\r\\n        }\\r\\n        System.out.println(\\\"图片复制成功\\\");\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    } finally {\\r\\n        // 关闭流（释放资源）\\r\\n        try {\\r\\n            if (fis != null) fis.close();\\r\\n            if (fos != null) fos.close();\\r\\n        } catch (IOException e) {\\r\\n            e.printStackTrace();\\r\\n        }\\r\\n    }\\r\\n}\\r\\n6.2 字符流示例（读写文本文件）\\r\\npublic static void readTextFile() {\\r\\n    FileReader fr = null;\"},{\"id\":50,\"segmentNo\":16,\"pageNo\":14,\"sectionTitle\":\"第14页 · 第2段 ·     try {\",\"contentText\":\"    BufferedReader br = null; // 缓冲字符流，提高效率\\r\\n    try {\\r\\n        fr = new FileReader(\\\"test.txt\\\");\\r\\n        br = new BufferedReader(fr);\"},{\"id\":51,\"segmentNo\":17,\"pageNo\":15,\"sectionTitle\":\"第15页 · 第1段 ·         // 按行读取文本\",\"contentText\":\"        String line;\\r\\n        // 按行读取文本\\r\\n        while ((line = br.readLine()) != null) {\\r\\n            System.out.println(line);\\r\\n        }\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    } finally {\\r\\n        try {\\r\\n            if (br != null) br.close();\\r\\n            if (fr != null) fr.close();\\r\\n        } catch (IOException e) {\\r\\n            e.printStackTrace();\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 写入文本文件\\r\\npublic static void writeTextFile() {\\r\\n    FileWriter fw = null;\\r\\n    BufferedWriter bw = null;\\r\\n    try {\\r\\n        // true表示追加写入，默认覆盖\\r\\n        fw = new FileWriter(\\\"test.txt\\\", true);\\r\\n        bw = new BufferedWriter(fw);\\r\\n        bw.write(\\\"Hello Java\\\");\\r\\n        bw.newLine(); // 换行\\r\\n        System.out.println(\\\"写入成功\\\");\\r\\n    } catch (IOException e) {\\r\\n        e.printStackTrace();\\r\\n    } finally {\\r\\n        try {\\r\\n            if (bw != null) bw.close();\"},{\"id\":52,\"segmentNo\":18,\"pageNo\":15,\"sectionTitle\":\"第15页 · 第2段 ·         }\",\"contentText\":\"            if (fw != null) fw.close();\\r\\n        } catch (IOException e) {\\r\\n            e.printStackTrace();\\r\\n        }\\r\\n    }\\r\\n}\"},{\"id\":53,\"segmentNo\":19,\"pageNo\":16,\"sectionTitle\":\"第16页 · 第1段 · 七、多线程（约 600 字）\",\"contentText\":\"七、多线程（约 600 字）\\r\\n7.1 线程概念\\r\\n线程是程序执行的最小单位，一个进程可包含多个线程，多线程可并发执行，提高程序效率。\\r\\n7.2 线程创建方式\\r\\n7.2.1 继承 Thread 类\\r\\nclass MyThread extends Thread {\\r\\n    @Override\\r\\n    public void run() {\\r\\n        // 线程执行逻辑\\r\\n        for (int i = 0; i < 10; i++) {\\r\\n            System.out.println(Thread.currentThread().getName() + \\\":\\\" + i);\\r\\n            try {\\r\\n                Thread.sleep(100); // 线程休眠100毫秒\\r\\n            } catch (InterruptedException e) {\\r\\n                e.printStackTrace();\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        MyThread thread1 = new MyThread();\\r\\n        MyThread thread2 = new MyThread();\\r\\n        thread1.setName(\\\"线程1\\\");\\r\\n        thread2.setName(\\\"线程2\\\");\\r\\n        thread1.start(); // 启动线程（调用run方法）\\r\\n        thread2.start();\\r\\n    }\\r\\n}\"},{\"id\":54,\"segmentNo\":20,\"pageNo\":17,\"sectionTitle\":\"第17页 · 第1段 · 7.2.2 实现 Runnable 接口\",\"contentText\":\"7.2.2 实现 Runnable 接口\\r\\nclass MyRunnable implements Runnable {\\r\\n    @Override\\r\\n    public void run() {\\r\\n        for (int i = 0; i  i++) {\\r\\n            System.out.println(Thread.currentThread().getName() + \\\":\\\" + i);\\r\\n            try {\\r\\n                Thread.sleep(100);\\r\\n            } catch (InterruptedException e) {\\r\\n                e.printStackTrace();\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n// 测试\\r\\npublic class Test {\\r\\n    public static void main(String[] args) {\\r\\n        Thread thread1 = new Thread(new MyRunnable(), \\\"线程1\\\");\\r\\n        Thread thread2 = new Thread(new MyRunnable(), \\\"线程2\\\");\\r\\n        thread1.start();\\r\\n        thread2.start();\\r\\n    }\\r\\n}\\r\\n7.2.3 实现 Callable 接口（带返回值）\\r\\nclass MyCallable implements Callable\\r\\n    @Override\\r\\n    public Integer call() throws Exception {\\r\\n        int sum = 0;\\r\\n        for (int i = 1; i 0; i++) {\\r\\n            sum += i;\\r\\n        }\\r\\n        return sum; // 返回结果\"},{\"id\":55,\"segmentNo\":21,\"pageNo\":17,\"sectionTitle\":\"第17页 · 第2段 ·     }\",\"contentText\":\"    }\\r\\n}\\r\\n// 测试\"},{\"id\":56,\"segmentNo\":22,\"pageNo\":18,\"sectionTitle\":\"第18页 · 第1段 · public class Test {\",\"contentText\":\"public class Test {\\r\\n    public static void main(String[] args) throws ExecutionException, InterruptedException {\\r\\n        Callable = new MyCallable();\\r\\n        FutureTaskTask = new FutureTaskcallable);\\r\\n        new Thread(futureTask).start();\\r\\n        Integer result = futureTask.get(); // 获取返回值（阻塞等待）\\r\\n        System.out.println(\\\"1-100求和：\\\" + result); // 输出：5050\\r\\n    }\\r\\n}\\r\\n7.3 线程状态与控制\\r\\n线程生命周期包括：新建（New）、就绪（Runnable）、运行（Running）、阻塞（Blocked）、死\\r\\n亡（Terminated）。\\r\\n常用线程控制方法：\\r\\n◦ start()：启动线程，进入就绪状态；\\r\\n◦ run()：线程执行逻辑；\\r\\n◦ sleep(long ms)：线程休眠，进入阻塞状态；\\r\\n◦ join()：等待线程执行完毕；\\r\\n◦ synchronized：同步锁，解决线程安全问题。\\r\\n线程安全示例（同步代码块）：\\r\\nclass TicketSale implements Runnable {\\r\\n    private int ticket = 100;\\r\\n    private Object lock = new Object(); // 锁对象\\r\\n    @Override\\r\\n    public void run() {\\r\\n        while (true) {\\r\\n            synchronized (lock) { // 同步代码块，保证原子性\\r\\n                if (ticket > 0) {\"},{\"id\":57,\"segmentNo\":23,\"pageNo\":18,\"sectionTitle\":\"第18页 · 第2段 ·                     System.out.p\",\"contentText\":\"                    System.out.println(Thread.currentThread().getName() + \\\"售出第\\\" + ticket + \\\"张票\\\");\\r\\n                    ticket--;\\r\\n                    try {\\r\\n                        Thread.sleep(50);\\r\\n                    } catch (InterruptedException e) {\\r\\n                        e.printStackTrace();\"},{\"id\":58,\"segmentNo\":24,\"pageNo\":19,\"sectionTitle\":\"第19页 · 第1段 ·                 }\",\"contentText\":\"                    }\\r\\n                } else {\\r\\n                    break;\\r\\n                }\\r\\n            }\\r\\n        }\\r\\n    }\\r\\n}\\r\\n八、注解与反射（约 300 字）\\r\\n8.1 注解\\r\\n注解（Annotation）用于修饰类、方法、变量，提供元数据信息，常用内置注解：\\r\\n◦ @Override：标识方法重写；\\r\\n◦ @Deprecated：标识方法已过时；\\r\\n◦ @SuppressWarnings：抑制编译器警告。\\r\\n自定义注解示例：\\r\\n// 定义注解\\r\\n@Retention(RetentionPolicy.RUNTIME) // 注解保留到运行时\\r\\n@Target(ElementType.METHOD) // 注解作用于方法\\r\\npublic @interface MyAnnotation {\\r\\n    String value() default \\\"\\\"; // 注解属性\\r\\n}\\r\\n// 使用注解\\r\\npublic class Test {\\r\\n    @MyAnnotation(\\\"测试方法\\\")\\r\\n    public void test() {\\r\\n        System.out.println(\\\"注解测试\\\");\\r\\n    }\\r\\n}\\r\\n8.2 反射\"},{\"id\":59,\"segmentNo\":25,\"pageNo\":20,\"sectionTitle\":\"第20页 · 第1段 · 为Class。\",\"contentText\":\"反射（Reflection）允许程序在运行时获取类的信息（属性、方法、构造器）并操作，核心类\\r\\n为Class。\\r\\n示例（通过反射调用方法）：\\r\\npublic class Test {\\r\\n    public void sayHello(String name) {\\r\\n        System.out.println(\\\"Hello \\\" + name);\\r\\n    }\\r\\n    public static void main(String[] args) throws Exception {\\r\\n        // 获取Class对象\\r\\n        Class;\\r\\n        // 创建对象\\r\\n        Object obj = clazz.newInstance();\\r\\n        // 获取方法（参数：方法名、参数类型）\\r\\n        Method method = clazz.getMethod(\\\"sayHello\\\", String.class);\\r\\n        // 调用方法（参数：对象、方法参数）\\r\\n        method.invoke(obj, \\\"Java\\\"); // 输出：Hello Java\\r\\n    }\\r\\n}\\r\\n九、Java 框架简介（约 200 字）\\r\\nJava 主流框架用于简化企业级开发：\\r\\n◦ Spring：核心是 IoC（控制反转）和 AOP（面向切面编程），提供依赖注入、事务管理等功能，是企\\r\\n业级开发的基石；\\r\\n◦ Spring Boot：基于 Spring，简化配置，实现 “开箱即用”，降低框架使用门槛；\\r\\n◦ MyBatis：持久层框架，简化 JDBC 操作，通过 XML 或注解映射数据库操作；\\r\\n◦ Spring MVC：Web 层框架，实现 MVC 设计模式，处理请求和响应；\\r\\n◦ Spring Cloud：微服务架构框架，提供服务注册发现、负载均衡、熔断等功能。\\r\\n这些框架相互配合，形成了 Java EE 开发的主流技术栈（SSM：Spring+Spring MVC+MyBatis，\"},{\"id\":60,\"segmentNo\":26,\"pageNo\":20,\"sectionTitle\":\"第20页 · 第2段 · Spring Boot+Spring Cloud）。\",\"contentText\":\"Spring Boot+Spring Cloud）。\\r\\n（注：文档部分内容可能由 AI 生成）\"}]}','SUCCESS',NULL,'2026-04-20 14:21:13','2026-04-20 14:21:13','2026-04-20 14:21:31','2026-04-20 14:21:31'),(59,18,127,'task.submit_summary','{\"materialId\":7,\"summaryType\":\"STANDARD\",\"saveAsNote\":true}','{\"id\":29,\"userId\":3,\"taskType\":\"SUMMARY\",\"bizType\":\"MATERIAL\",\"bizId\":7,\"status\":\"PENDING\",\"progressRate\":0,\"retryCount\":0,\"priority\":5,