INSERT INTO `material_segment` VALUES (1,1,1,NULL,'??????? ???','????????????????????????????????????,??????????????????????????????????',17,NULL,'PENDING',NULL,NULL,NULL,NULL,'2026-04-16 14:06:54','2026-04-16 14:06:54'),(13,5,1,NULL,'第1段','计算机网络核心知识全解析（2026 版）\r\n一、计算机网络基础理论\r\n（一）定义与核心价值\r\n计算机网络是指将地理上分散的、具有独立功能的计算机系统，通过通信设备和传输介质连接，由网\r\n络操作系统、网络协议及网络管理软件实现资源共享和信息交换的系统。其核心价值体现在三大维度\r\n：数据传输（如文件交互、视频流传输）、资源共享（硬件设备、软件应用、数据存储）、分布式处\r\n理（多终端协同完成复杂任务），已成为数字经济时代的基础设施。\r\n（二）网络分类与拓扑结构\r\n1. 按覆盖范围分类\r\n◦ 局域网（LAN）：覆盖范围≤10km，\r\n企业园区网、校园网，传输速率可达 10Gbps 以上，采用以太网（Ethernet）为核心技术。如\r\n◦ 城域网（MAN）：覆盖城市级区域（10-100km），用于连接多个局域网，典型应用为城市政务网、\r\n运营商骨干网。\r\n◦ 广域网（WAN）：覆盖跨区域甚至全球范围，依赖光纤、卫星等长距离传输介质，互联网是最大的广\r\n域网实例。\r\n◦ 物联网（IoT）：特殊类型的泛在网络，连接海量终端设备，2026 年全球终端连接数已突破 60 亿，预\r\n计 2028 年将达百亿级规模。\r\n2. 主流拓扑结构\r\n◦ 星型结构：以中心设备（交换机、路由器）为核心，稳定性高、故障易排查，是当前局域网的主流架\r\n构。\r\n◦ 总线型结构：所有设备共享一条传输总线，成本低但可靠性差，已逐步被星型结构取代。\r\n◦ 环形结构：设备首尾相连形成闭环，适用于工业控制网络，如令牌环网（Token Ring）。\r\n◦ 网状结构：多设备间两两互联，容错性强，用于骨干网和数据中心网络。\r\n（三）网络体系结构\r\n1. OSI 七层参考模型\r\n从下至上依次为：物理层（传输介质、接口标准）、数据链路层（帧封装、差错控制）、网络层（路\r\n由选择、地址分配）、传输层（端到端可靠传输）、会话层（建立通信会话）、表示层（数据加密、\r\n格式转换）、应用层（提供用户服务）。该模型为网络协议设计提供了标准化框架，但实际应用中更\r\n倾向于简化的 TCP/IP 模型。\r\n2. TCP/IP 四层模型\r\n◦ 网络接口层：对应 OSI 物理层 + 数据链路层，负责硬件接口和帧传输。\r\n◦ 网络层：核心协议为 IP（IPv4/IPv6），实现路由转发和地址解析（ARP 协议）。',245,NULL,'SUCCESS','doubao-embedding-vision-251215',19,'13','2026-04-18 13:43:20','2026-04-16 17:26:13','2026-04-16 17:26:13'),(14,5,2,NULL,'第2段','◦ 传输层：提供可靠传输（TCP）和不可靠传输（UDP），TCP 通过三次握手建立连接、四次挥手释放\r\n连接，保障数据完整性。\r\n◦ 应用层：包含 HTTP、FTP、DNS 等协议，直接面向用户应用场景。\r\n二、计算机网络核心技术\r\n（一）网络层关键技术\r\n1. IP 地址与子网划分\r\n◦ IPv4：32 位地址，采用点分十进制表示（如 192.168.1.1），地址资源已枯竭，通过 NAT（网络地址转\r\n换）技术缓解压力。\r\n◦ IPv6：128 位地址，采用冒分十六进制表示（如 2001:0db8:85a3:0000:0000:8a2e:0370:7334），支持\r\n无限地址空间，2026 年全球主流网站 IPv6 部署率已超 40%，我国政务系统已全面支持 IPv6 访问。\r\n◦ 子网划分：通过子网掩码（如 255.255.255.0）将大网络划分子网，提升地址利用率和网络安全性。\r\n2. 路由技术\r\n◦ 静态路由：手动配置路由表，适用于小型网络。\r\n◦ 动态路由：通过路由协议自动更新路由表，主流协议包括 RIP（距离矢量协议）、OSPF（链路状态协\r\n议）、BGP（自治系统间路由协议）。\r\n◦ 软件定义路由（SDR）：分离路由控制平面与数据转发平面，提升路由灵活性，是 SDN（软件定义网\r\n络）的核心技术之一。\r\n（二）传输层协议解析\r\n1. TCP 协议\r\n◦ 核心机制：流量控制（滑动窗口协议）、拥塞控制（慢启动、拥塞避免、快速重传、快速恢复）。\r\n◦ 现代优化算法：Linux 默认采用 CUBIC 算法，适用于高带宽延迟积网络；BBR 算法基于带宽和延迟估\r\n计而非丢包检测，在 5G 和卫星网络中表现更优。\r\n◦ 应用场景：文件传输（FTP）、网页浏览（HTTP/HTTPS）、邮件发送（SMTP）等对可靠性要求高的\r\n场景。\r\n2. UDP 协议\r\n◦ 特点：无连接、低延迟、不保证可靠性，传输效率高于 TCP。\r\n◦ 应用场景：实时通信（视频通话、语音聊天）、在线游戏、物联网数据采集等对时延敏感的场景。\r\n（三）应用层协议演进\r\n1. HTTP 协议家族\r\n◦ HTTP/1.1：支持持久连接，但存在队头阻塞问题，同一连接中只能串行传输请求。\r\n◦ HTTP/2：采用二进制帧和多路复用技术，解决队头阻塞，提升并发性能。',245,NULL,'SUCCESS','doubao-embedding-vision-251215',19,'14','2026-04-18 13:43:20','2026-04-16 17:26:13','2026-04-16 17:26:13'),(15,5,3,NULL,'第3段','◦ HTTP/3：基于 QUIC 协议（UDP 封装），彻底消除传输层队头阻塞，支持 0-RTT/1-RTT 握手、无缝网\r\n络切换和强制加密，2026 年全球 Top1000 网站支持率已超 25%，Chrome、Firefox 等浏览器默认开\r\n启支持。\r\n2. 其他核心协议\r\n◦ DNS：域名系统，将域名（如www.baidu.com）解析为 IP 地址，支持递归查询和迭代查询，2026 年\r\n已广泛部署 DNS-over-HTTPS（DoH）协议，提升解析安全性。\r\n◦ FTP：文件传输协议，支持上传下载，分为主动模式和被动模式。\r\n◦ MQTT：物联网专用协议，轻量级、低功耗，适用于传感器数据传输，是《物联网行动方案（2026—2\r\n028 年）》指定的核心协议之一。\r\n（四）5G-Advanced 与新一代网络技术\r\n1. 5G-A 技术特性\r\n◦ 性能指标：峰值速率达 10Gbps（下行）/1Gbps（上行），时延低至 5ms，连接密度提升 10 倍。\r\n◦ 核心技术：智能超表面（RIS）、通感一体、内生智能，支持网络自动优化和环境感知。\r\n◦ 典型应用：全息通信、工业视觉检测（毫米级精度）、L4 级自动驾驶、AI 手术机器人实时操控。\r\n2. 物联网 “端 - 边 - 云” 架构\r\n◦\r\n架构组成：终端（传感器、智能设备）、边缘节点（边缘网关、边缘计算节点）、云端平台（数据中\r\n心、AI 模型库）。\r\n◦ 技术优势：数据本地处理降低时延，云端协同提升智能决策能力，适配千兆光网、5G 等多网络环境。\r\n◦ 政策驱动：九部门明确要求 2028 年物联网核心产业规模突破 3.5 万亿元，推动 AI 大模型轻量化部署至\r\n终端和边缘节点。\r\n三、计算机网络安全体系\r\n（一）网络安全威胁类型\r\n1. 新型钓鱼攻击\r\n◦ 特点：融合 AI 技术实现语义伪装，采用多模态渗透（文本、语音、视频、二维码），通过精准画像和\r\n供应链渗透提升攻击成功率，利用即时通信软件和时间对抗技术增强隐蔽性。\r\n◦ 典型案例：2024 年江苏无锡某公司财务人员点击伪造税务稽查链接，导致电脑被木马入侵；西北能源\r\n基地 DNS 篡改事件，攻击者通过供应链植入恶意代码。\r\n2. 其他主要威胁',237,NULL,'SUCCESS','doubao-embedding-vision-251215',19,'15','2026-04-18 13:43:20','2026-04-16 17:26:13','2026-04-16 17:26:13'),(16,5,4,NULL,'第4段','◦ 网络攻击：DDoS 攻击（分布式拒绝服务）、SQL 注入、勒索病毒（如 WannaCry 变种）。\r\n◦ 数据泄露：用户隐私数据（身份证号、手机号）、企业商业机密、政务敏感信息泄露。\r\n◦ 设备劫持：物联网设备被植入恶意程序，形成僵尸网络（如 Mirai botnet）。\r\n（二）安全防护技术与策略\r\n1. 个人层面防护\r\n◦ 身份认证：采用 “PIN 码 + 硬件密钥” 组合验证，避免生物信息（人脸、声纹）泄露。\r\n◦ 行为规范：不点击陌生链接和附件，通过官方渠道核实工作通知，定期更新操作系统和应用软件。\r\n2. 机构层面防护\r\n◦ 技术防护：部署防火墙、入侵检测系统（IDS）、入侵防御系统（IPS），实施数据 “加密 + 脱敏 + 访\r\n问控制” 三重防护。\r\n◦ 供应链管理：对关键供应商开展代码审计和漏洞溯源，定期进行钓鱼邮件演练和安全检测。\r\n◦ 合规建设：遵循《网络安全法》《数据安全法》，建立安全事件应急预案。\r\n3. 社会层面防护\r\n◦ 宣传教育：通过线下宣讲、情景短剧等形式开展安全宣教，提升全民安全意识。\r\n◦ 协同治理：建立钓鱼邮件举报奖励机制，开通多渠道举报通道，构建跨部门安全协同平台。\r\n（三）新兴安全技术\r\n1. 零信任架构\r\n◦ 核心理念：“永不信任，始终验证”，基于最小权限原则，对每个访问请求进行身份认证和权限校验\r\n，适用于混合云、远程办公等场景。\r\n2. 量子加密技术\r\n◦ 原理：利用量子力学的测不准原理和量子纠缠特性，实现绝对安全的密钥传输，抵御量子计算机对传\r\n统加密算法的破解威胁，2026 年已在政务、金融领域试点应用。\r\n3. AI 安全防护\r\n◦ 应用：通过 AI 算法实时监测网络异常流量，识别新型恶意代码，自动响应安全事件，提升防护效率和\r\n准确性。\r\n四、计算机网络前沿应用\r\n（一）工业互联网\r\n◦ 核心架构：基于 5G-A 和边缘计算，实现设备互联、数据采集、智能分析和远程控制。\r\n◦ 应用场景：智能工厂（设备预测性维护、柔性生产）、智慧港口（自动化码头、无人起重机）、智慧\r\n矿山（远程采矿、环境监测），2026 年工业互联网平台接入设备数已超 15 亿台。\r\n（二）智慧城市\r\n◦ 关键应用：智能交通（车路协同、智能信号灯）、环境监测（空气质量、噪音污染实时感知）、智慧',244,NULL,'SUCCESS','doubao-embedding-vision-251215',19,'16','2026-04-18 13:43:20','2026-04-16 17:26:13','2026-04-16 17:26:13'),(17,5,5,NULL,'第5段','安防（视频监控、异常行为识别）、智慧能源（智能电网、分布式能源调度）。\r\n◦ 技术支撑：物联网多模态感知、5G-A 通感一体、大数据分析和 AI 决策。\r\n（三）远程医疗与智慧教育\r\n◦ 远程医疗：5G-A 支持 AI 手术机器人实时操控、远程会诊和高清医学影像传输，打破医疗资源地域限制\r\n。\r\n◦\r\n智慧教育：VR/AR 沉浸式学习、在线直播课堂、教育资源云共享，2026 年 “5G + 智慧教育” 覆盖全\r\n国 80% 以上的中小学。\r\n五、计算机网络未来趋势\r\n（一）技术融合加速\r\n◦ 网络与 AI 深度融合：AI 赋能网络自动化运维、智能调度和安全防护，网络成为 AI 应用的重要载体。\r\n◦ 多网协同发展：5G-A 与卫星互联网、千兆光网、物联网融合，构建天地一体、固移融合的泛在网络。\r\n（二）智能化与自主化\r\n◦ 自主网络：具备自配置、自优化、自修复能力，降低人工运维成本，适应复杂动态的网络环境。\r\n◦ 智能体演进：物联网终端从 “感知节点” 升级为 “先进智能体”，具备自主决策和执行能力，推动 “\r\n万物智行” 发展。\r\n（三）安全与隐私强化\r\n◦ 隐私计算：在保护数据隐私的前提下实现数据共享和分析，支持联邦学习、安全多方计算等技术。\r\n◦ 量子安全：大规模部署量子加密网络，构建抗量子计算攻击的安全体系。\r\n（四）产业生态重构\r\n◦ 利润重心转移：从 “连接服务” 向 “智能服务” 转变，端侧 AI 芯片、行业专用模型、高端传感器成\r\n为产业竞争焦点。\r\n◦ 开源生态崛起：物联网操作系统开源化趋势明显，打破硬件生态割裂，降低产业准入门槛。\r\n结语\r\n计算机网络作为数字社会的 “神经网络”，其技术演进始终围绕 “更高速、更智能、更安全、更泛在\r\n” 的目标推进。从 TCP/IP 协议的诞生到 HTTP/3 的普及，从 5G 到 5G-A 的跨越，从物联网到 “万物\r\n智行” 的升级，计算机网络不仅改变了信息传输方式，更重构了产业形态和社会生活。未来，随着 AI\r\n、量子技术、物联网的深度融合，计算机网络将面临新的机遇和挑战，持续为数字经济发展提供核心\r\n动力。掌握计算机网络核心知识，不仅是技术从业者的必备能力，也是每个数字公民适应未来社会的\r\n基础要求。\r\n（注：文档部分内容可能由 AI 生成）',242,NULL,'SUCCESS','doubao-embedding-vision-251215',19,'17','2026-04-18 13:43:20','2026-04-16 17:26:13','2026-04-16 17:26:13'),(18,6,1,NULL,'第1段','Java 核心知识全面梳理\r\n一、Java 语言概述（约 500 字）\r\n1.1 语言简介\r\nJava 是由 Sun Microsystems（后被 Oracle 收购）于 1995 年推出的面向对象编程语言，其设计理念是\r\n “一次编写，到处运行（Write Once, Run Anywhere, WORA）”。核心优势在于跨平台性，通过 Java\r\n 虚拟机（JVM）实现 ——Java 源代码编译为字节码（.class 文件），再由不同平台的 JVM 解释执行，\r\n无需修改代码即可在 Windows、Linux、macOS 等系统运行。\r\n1.2 主要特点\r\n◦ 面向对象：封装、继承、多态三大特性，符合现实世界建模逻辑；\r\n◦ 跨平台：依赖 JVM 屏蔽底层系统差异，字节码具备平台无关性；\r\n◦ 安全性：内置安全机制，避免指针直接操作，防止内存泄露和恶意攻击；\r\n◦ 健壮性：强类型检查、异常处理机制，提升程序稳定性；\r\n◦ 多线程：原生支持多线程编程，适合并发场景开发。\r\n1.3 应用场景\r\nJava 广泛应用于企业级开发（Spring、MyBatis 框架）、移动开发（Android 应用）、大数据处理（-\r\nHadoop 生态）、中间件开发（Tomcat、Nacos）等领域，是当前最主流的编程语言之一。\r\n二、Java 基础语法（约 800 字）\r\n2.1 数据类型\r\nJava 数据类型分为基本类型和引用类型，其中基本类型共 8 种：\r\n类型 占用空间 取值范围\r\nbyte 1 字节 -128 ~ 127\r\nshort 2 字节 -32768 ~ 32767\r\nint 4 字节 -2³¹ ~ 2³¹-1\r\nlong 8 字节 -2v³ ~ 2v³-1\r\nfloat 4 字节 单精度浮点数，约 ±3.4e38\r\ndouble 8 字节 双精度浮点数，约 ±1.8e308\r\nchar 2 字节 Unicode 字符（0 ~ 65535）\r\nboolean 1 字节 true/false\r\n引用类型包括类、接口、数组、枚举等，本质是指向对象的内存地址。\r\n2.2 变量与常量\r\n◦ 变量：需声明数据类型，语法为类型 变量名 = 初始值;，如int age = 20;；',237,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'18','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(19,6,2,NULL,'第2段','◦ 常量：用final修饰，一旦赋值不可修改，语法为final 类型 常量名 = 值;，如final double PI = 3.\r\n14159;（常量名通常大写）。\r\n2.3 运算符\r\n◦ 算术运算符：+-*/%++--（注意++前置自增与后置自增的区别）；\r\n◦ 关系运算符：`==、!=、>、<、>=、返回 boolean 类型；\r\n◦ 逻辑运算符：&&（短路与）、||（短路或）、!（非）；\r\n◦ 赋值运算符：=+=-=*=/=等；\r\n◦ 三元运算符：条件表达式 ? 表达式1 : 表达式2，如int max = a > b ? a : b;。\r\n2.4 流程控制\r\n2.4.1 条件语句\r\n// if-else语句\r\nif (age >= 18) {\r\n    System.out.println(\"成年人\");\r\n} else if (age >= 6) {\r\n    System.out.println(\"青少年\");\r\n} else {\r\n    System.out.println(\"儿童\");\r\n}\r\n// switch语句（JDK7+支持String类型）\r\nswitch (season) {\r\n    case \"春季\":\r\n        System.out.println(\"3-5月\");\r\n        break;\r\n    case \"夏季\":\r\n        System.out.println(\"6-8月\");\r\n        break;\r\n    default:\r\n        System.out.println(\"未知季节\");\r\n}\r\n2.4.2 循环语句\r\n// for循环\r\nfor (int i = 0; i  i++) {\r\n    System.out.println(i); // 输出0-9\r\n}\r\n// while循环\r\nint j = 0;\r\nwhile (j 0) {\r\n    System.out.println(j);\r\n    j++;\r\n}\r\n// do-while循环（至少执行一次）\r\nint k = 0;\r\ndo {\r\n    System.out.println(k);\r\n    k++;\r\n} while (k < 10);\r\n2.5 数组',247,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'19','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(20,6,3,NULL,'第3段','数组是存储同一类型数据的固定长度容器，声明与初始化方式：\r\n// 声明并初始化\r\nint[] arr1 = {1, 2, 3};\r\n// 指定长度初始化\r\nint[] arr2 = new int[3];\r\narr2[0] = 1;\r\narr2[1] = 2;\r\narr2[2] = 3;\r\n// 遍历数组（增强for循环）\r\nfor (int num : arr1) {\r\n    System.out.println(num);\r\n}\r\n三、面向对象编程（约 1000 字）\r\n3.1 核心概念\r\n面向对象编程（OOP）以 “对象” 为核心，将数据和行为封装为一个整体，通过继承和多态实现代码\r\n复用和扩展。\r\n3.2 类与对象\r\n◦ 类：对象的模板，定义对象的属性（成员变量）和行为（成员方法）；\r\n◦ 对象：类的实例化结果，通过new关键字创建。\r\n示例代码：\r\n// 定义Person类\r\nclass Person {\r\n    // 成员变量（属性）\r\n    String name;\r\n    int age;\r\n    // 成员方法（行为）\r\n    public void eat() {\r\n        System.out.println(name + \"正在吃饭\");\r\n    }\r\n    public void sleep() {\r\n        System.out.println(name + \"正在睡觉\");\r\n    }\r\n}\r\n// 创建对象并使用\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        Person person = new Person();\r\n        person.name = \"张三\";\r\n        person.age = 25;\r\n        person.eat(); // 输出：张三正在吃饭\r\n        person.sleep(); // 输出：张三正在睡觉\r\n    }\r\n}\r\n3.3 封装\r\n封装是将对象的属性私有化，通过公共的getter/setter方法控制访问，隐藏内部实现细节，提升安\r\n全性。\r\n示例代码：\r\nclass Person {',245,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'20','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(21,6,4,NULL,'第4段','    // 私有成员变量（仅本类可访问）\r\n    private String name;\r\n    private int age;\r\n    // getter方法（获取属性值）\r\n    public String getName() {\r\n        return name;\r\n    }\r\n    // setter方法（设置属性值，可添加逻辑校验）\r\n    public void setName(String name) {\r\n        if (name != null && !name.isEmpty()) {\r\n            this.name = name;\r\n        } else {\r\n            System.out.println(\"姓名不能为空\");\r\n        }\r\n    }\r\n    public int getAge() {\r\n        return age;\r\n    }\r\n    public void setAge(int age) {\r\n        if (age >= 0 && age  120) {\r\n            this.age = age;\r\n        } else {\r\n            System.out.println(\"年龄无效\");\r\n        }\r\n    }\r\n}\r\n3.4 继承\r\n继承允许子类继承父类的属性和方法，子类可扩展新功能或重写父类方法，关键字为extends。Java \r\n支持单继承（一个子类只能有一个父类），但可通过接口实现多继承效果。\r\n示例代码：\r\n// 父类\r\nclass Animal {\r\n    public void move() {\r\n        System.out.println(\"动物会移动\");\r\n    }\r\n}\r\n// 子类继承父类\r\nclass Dog extends Animal {\r\n    // 重写父类方法\r\n    @Override\r\n    public void move() {\r\n        System.out.println(\"狗会跑\");\r\n    }\r\n    // 子类扩展方法\r\n    public void bark() {',249,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'21','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(22,6,5,NULL,'第5段','        System.out.println(\"狗会叫\");\r\n    }\r\n}\r\n// 测试\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        Dog dog = new Dog();\r\n        dog.move(); // 输出：狗会跑（重写后）\r\n        dog.bark(); // 输出：狗会叫（扩展方法）\r\n    }\r\n}\r\n3.5 多态\r\n多态是指同一行为在不同对象上表现出不同形态，实现条件：\r\n1. 子类继承父类；\r\n2. 子类重写父类方法；\r\n3. 父类引用指向子类对象。\r\n示例代码：\r\nclass Animal {\r\n    public void sound() {\r\n        System.out.println(\"动物发出声音\");\r\n    }\r\n}\r\nclass Cat extends Animal {\r\n    @Override\r\n    public void sound() {\r\n        System.out.println(\"猫喵喵叫\");\r\n    }\r\n}\r\nclass Bird extends Animal {\r\n    @Override\r\n    public void sound() {\r\n        System.out.println(\"鸟叽叽叫\");\r\n    }\r\n}\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        Animal animal1 = new Cat();\r\n        Animal animal2 = new Bird();\r\n        animal1.sound(); // 输出：猫喵喵叫\r\n        animal2.sound(); // 输出：鸟叽叽叫\r\n    }\r\n}\r\n3.6 接口与抽象类\r\n◦ 抽象类：用abstract修饰，包含抽象方法（无实现）和普通方法，不能实例化，需子类继承并实现抽\r\n象方法；\r\n◦ 接口：用interface修饰，仅包含抽象方法（JDK8 + 支持默认方法和静态方法），类通过-',248,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'22','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(23,6,6,NULL,'第6段','implements实现接口，可多实现。\r\n示例（接口）：\r\ninterface Flyable {\r\n    void fly(); // 抽象方法\r\n}\r\nclass Bird implements Flyable {\r\n    @Override\r\n    public void fly() {\r\n        System.out.println(\"鸟展翅飞翔\");\r\n    }\r\n}\r\nclass Plane implements Flyable {\r\n    @Override\r\n    public void fly() {\r\n        System.out.println(\"飞机引擎驱动飞行\");\r\n    }\r\n}\r\n四、Java 核心类库（约 600 字）\r\n4.1 String 类\r\nString 是不可变字符序列，常用方法：\r\nString str = \"Hello Java\";\r\nSystem.out.println(str.length()); // 长度：9\r\nSystem.out.println(str.charAt(0)); // 获取索引0字符：\'H\'\r\nSystem.out.println(str.substring(6)); // 截取子串：\"Java\"\r\nSystem.out.println(str.equals(\"hello java\")); // 比较内容：false（区分大小写）\r\nSystem.out.println(str.toLowerCase()); // 转小写：\"hello java\"\r\nSystem.out.println(str.split(\" \")); // 分割字符串：[\"Hello\", \"Java\"]\r\n注意：String 不可变，每次修改都会创建新对象，频繁修改建议使用StringBuilder（非线程安全）\r\n或StringBuffer（线程安全）。\r\n4.2 包装类\r\n基本类型的包装类用于将基本类型转换为对象，支持装箱（基本类型→对象）和拆箱（对象→基本类\r\n型）：\r\n基本类型 包装类\r\nint Integer\r\nchar Character\r\ndouble Double\r\n示例：\r\n// 装箱',238,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'23','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(24,6,7,NULL,'第7段','Integer num1 = 10; // 自动装箱（等价于Integer.valueOf(10)）\r\n// 拆箱\r\nint num2 = num1; // 自动拆箱（等价于num1.intValue()）\r\n// 常用方法\r\nSystem.out.println(Integer.parseInt(\"123\")); // 字符串转int：123\r\nSystem.out.println(Integer.MAX_VALUE); // 最大值：2147483647\r\n4.3 日期时间类\r\nJDK8 + 推荐使用java.time包下的日期时间类（替代旧版Date和Calendar）：\r\n// 获取当前日期\r\nLocalDate today = LocalDate.now();\r\nSystem.out.println(today); // 输出：2024-05-20（格式示例）\r\n// 获取当前时间\r\nLocalTime now = LocalTime.now();\r\nSystem.out.println(now); // 输出：14:30:25（格式示例）\r\n// 日期计算\r\nLocalDate tomorrow = today.plusDays(1);\r\nSystem.out.println(tomorrow); // 输出：2024-05-21\r\n// 格式化日期\r\nDateTimeFormatter formatter = DateTimeFormatter.ofPattern(\"yyyy年MM月dd日\");\r\nString formattedDate = today.format(formatter);\r\nSystem.out.println(formattedDate); // 输出：2024年05月20日\r\n4.4 集合框架（约 700 字）\r\nJava 集合框架（java.util包）用于存储和操作多个对象，分为Collection和Map两大体系：\r\n4.4.1 Collection 接口\r\nCollection包含List（有序、可重复）、Set（无序、不可重复）、Queue（队列）子接口：\r\n4.4.1.1 List 接口\r\n常用实现类：ArrayList（数组实现，查询快、增删慢）、LinkedList（链表实现，增删快、查询慢\r\n）。',248,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'24','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(25,6,8,NULL,'第8段','示例（ArrayList）：\r\nList> list = new ArrayList();\r\n// 添加元素\r\nlist.add(\"苹果\");\r\nlist.add(\"香蕉\");\r\nlist.add(\"橙子\");\r\n// 插入元素\r\nlist.add(1, \"葡萄\");\r\n// 遍历\r\nfor (String fruit : list) {\r\n    System.out.println(fruit); // 输出：苹果、葡萄、香蕉、橙子\r\n}\r\n// 获取元素\r\nSystem.out.println(list.get(2)); // 输出：香蕉\r\n// 删除元素\r\nlist.remove(3);\r\n// 查找元素索引\r\nSystem.out.println(list.indexOf(\"香蕉\")); // 输出：2\r\n4.4.1.2 Set 接口\r\n常用实现类：HashSet（哈希表实现，无序）、TreeSet（红黑树实现，自然排序）。\r\n示例（HashSet）：\r\nSet = new HashSetset.add(\"张三\");\r\nset.add(\"李四\");\r\nset.add(\"张三\"); // 重复元素，添加失败\r\nSystem.out.println(set.size()); // 输出：2\r\n// 遍历\r\nIterator<String> iterator = set.iterator();\r\nwhile (iterator.hasNext()) {\r\n    System.out.println(iterator.next()); // 无序输出：张三、李四\r\n}\r\n4.4.2 Map 接口\r\nMap存储键值对（key-value），key 唯一，value 可重复，常用实现类：HashMap（哈希表实现，无序\r\n）、TreeMap（红黑树实现，按键排序）。\r\n示例（HashMap）：\r\nMap Integer> map = new HashMap<>();\r\n// 添加键值对\r\nmap.put(\"语文\", 90);\r\nmap.put(\"数学\", 95);\r\nmap.put(\"英语\", 88);\r\n// 获取value\r\nSystem.out.println(map.get(\"数学\")); // 输出：95\r\n// 遍历key',246,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'25','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(26,6,9,NULL,'第9段','for (String subject : map.keySet()) {\r\n    System.out.println(subject + \":\" + map.get(subject));\r\n}\r\n// 遍历键值对\r\nfor (Map.Entry : map.entrySet()) {\r\n    System.out.println(entry.getKey() + \":\" + entry.getValue());\r\n}\r\n// 判断key是否存在\r\nSystem.out.println(map.containsKey(\"物理\")); // 输出：false\r\n五、异常处理（约 400 字）\r\n5.1 异常概念\r\n异常是程序运行时出现的错误（如空指针、数组越界），Java 通过异常处理机制避免程序崩溃，核心\r\n类为Throwable，其下分为Error（严重错误，无法处理）和Exception（可处理异常）。\r\n5.2 异常处理方式\r\n5.2.1 try-catch-finally\r\ntry {\r\n    // 可能出现异常的代码\r\n    int[] arr = {1, 2, 3};\r\n    System.out.println(arr[3]); // 数组越界异常\r\n} catch (ArrayIndexOutOfBoundsException e) {\r\n    // 捕获指定异常并处理\r\n    System.out.println(\"异常信息：\" + e.getMessage()); // 输出：3\r\n} finally {\r\n    // 无论是否异常，都会执行（常用于资源释放）\r\n    System.out.println(\"程序执行完毕\");\r\n}\r\n5.2.2 throws 声明异常\r\n方法抛出异常，由调用者处理：\r\npublic static void readFile() throws IOException {\r\n    FileReader fr = new FileReader(\"test.txt\");\r\n    fr.close();\r\n}\r\n// 调用者处理异常\r\npublic static void main(String[] args) {\r\n    try {\r\n        readFile();',247,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'26','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(27,6,10,NULL,'第10段','    } catch (IOException e) {\r\n        e.printStackTrace();\r\n    }\r\n}\r\n5.2.3 自定义异常\r\n继承Exception或RuntimeException实现自定义异常：\r\n// 自定义异常类\r\nclass AgeException extends Exception {\r\n    public AgeException(String message) {\r\n        super(message);\r\n    }\r\n}\r\n// 使用自定义异常\r\npublic static void checkAge(int age) throws AgeException {\r\n    if (age  > 120) {\r\n        throw new AgeException(\"年龄无效：\" + age);\r\n    }\r\n}\r\n六、IO 流（约 500 字）\r\nIO 流用于文件读写、数据传输，按流向分为输入流（InputStream/Reader）和输出流（-\r\nOutputStream/Writer），按处理单位分为字节流（处理二进制文件）和字符流（处理文本文件）。\r\n6.1 字节流示例（复制图片）\r\npublic static void copyImage() {\r\n    FileInputStream fis = null;\r\n    FileOutputStream fos = null;\r\n    try {\r\n        // 输入流（读取源文件）\r\n        fis = new FileInputStream(\"source.jpg\");\r\n        // 输出流（写入目标文件）\r\n        fos = new FileOutputStream(\"target.jpg\");\r\n        byte[] buffer = new byte[1024]; // 缓冲区\r\n        int len;\r\n        // 读取数据并写入\r\n        while ((len = fis.read(buffer)) != -1) {\r\n            fos.write(buffer, 0, len);\r\n        }',247,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'27','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(28,6,11,NULL,'第11段','        System.out.println(\"图片复制成功\");\r\n    } catch (IOException e) {\r\n        e.printStackTrace();\r\n    } finally {\r\n        // 关闭流（释放资源）\r\n        try {\r\n            if (fis != null) fis.close();\r\n            if (fos != null) fos.close();\r\n        } catch (IOException e) {\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}\r\n6.2 字符流示例（读写文本文件）\r\npublic static void readTextFile() {\r\n    FileReader fr = null;\r\n    BufferedReader br = null; // 缓冲字符流，提高效率\r\n    try {\r\n        fr = new FileReader(\"test.txt\");\r\n        br = new BufferedReader(fr);\r\n        String line;\r\n        // 按行读取文本\r\n        while ((line = br.readLine()) != null) {\r\n            System.out.println(line);\r\n        }\r\n    } catch (IOException e) {\r\n        e.printStackTrace();\r\n    } finally {\r\n        try {\r\n            if (br != null) br.close();\r\n            if (fr != null) fr.close();\r\n        } catch (IOException e) {\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}\r\n// 写入文本文件',241,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'28','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(29,6,12,NULL,'第12段','public static void writeTextFile() {\r\n    FileWriter fw = null;\r\n    BufferedWriter bw = null;\r\n    try {\r\n        // true表示追加写入，默认覆盖\r\n        fw = new FileWriter(\"test.txt\", true);\r\n        bw = new BufferedWriter(fw);\r\n        bw.write(\"Hello Java\");\r\n        bw.newLine(); // 换行\r\n        System.out.println(\"写入成功\");\r\n    } catch (IOException e) {\r\n        e.printStackTrace();\r\n    } finally {\r\n        try {\r\n            if (bw != null) bw.close();\r\n            if (fw != null) fw.close();\r\n        } catch (IOException e) {\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}\r\n七、多线程（约 600 字）\r\n7.1 线程概念\r\n线程是程序执行的最小单位，一个进程可包含多个线程，多线程可并发执行，提高程序效率。\r\n7.2 线程创建方式\r\n7.2.1 继承 Thread 类\r\nclass MyThread extends Thread {\r\n    @Override\r\n    public void run() {\r\n        // 线程执行逻辑\r\n        for (int i = 0; i < 10; i++) {\r\n            System.out.println(Thread.currentThread().getName() + \":\" + i);\r\n            try {\r\n                Thread.sleep(100); // 线程休眠100毫秒',240,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'29','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(30,6,13,NULL,'第13段','            } catch (InterruptedException e) {\r\n                e.printStackTrace();\r\n            }\r\n        }\r\n    }\r\n}\r\n// 测试\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        MyThread thread1 = new MyThread();\r\n        MyThread thread2 = new MyThread();\r\n        thread1.setName(\"线程1\");\r\n        thread2.setName(\"线程2\");\r\n        thread1.start(); // 启动线程（调用run方法）\r\n        thread2.start();\r\n    }\r\n}\r\n7.2.2 实现 Runnable 接口\r\nclass MyRunnable implements Runnable {\r\n    @Override\r\n    public void run() {\r\n        for (int i = 0; i  i++) {\r\n            System.out.println(Thread.currentThread().getName() + \":\" + i);\r\n            try {\r\n                Thread.sleep(100);\r\n            } catch (InterruptedException e) {\r\n                e.printStackTrace();\r\n            }\r\n        }\r\n    }\r\n}\r\n// 测试\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        Thread thread1 = new Thread(new MyRunnable(), \"线程1\");',238,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'30','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(31,6,14,NULL,'第14段','        Thread thread2 = new Thread(new MyRunnable(), \"线程2\");\r\n        thread1.start();\r\n        thread2.start();\r\n    }\r\n}\r\n7.2.3 实现 Callable 接口（带返回值）\r\nclass MyCallable implements Callable\r\n    @Override\r\n    public Integer call() throws Exception {\r\n        int sum = 0;\r\n        for (int i = 1; i 0; i++) {\r\n            sum += i;\r\n        }\r\n        return sum; // 返回结果\r\n    }\r\n}\r\n// 测试\r\npublic class Test {\r\n    public static void main(String[] args) throws ExecutionException, InterruptedException {\r\n        Callable = new MyCallable();\r\n        FutureTaskTask = new FutureTaskcallable);\r\n        new Thread(futureTask).start();\r\n        Integer result = futureTask.get(); // 获取返回值（阻塞等待）\r\n        System.out.println(\"1-100求和：\" + result); // 输出：5050\r\n    }\r\n}\r\n7.3 线程状态与控制\r\n线程生命周期包括：新建（New）、就绪（Runnable）、运行（Running）、阻塞（Blocked）、死\r\n亡（Terminated）。\r\n常用线程控制方法：\r\n◦ start()：启动线程，进入就绪状态；\r\n◦ run()：线程执行逻辑；\r\n◦ sleep(long ms)：线程休眠，进入阻塞状态；\r\n◦ join()：等待线程执行完毕；\r\n◦ synchronized：同步锁，解决线程安全问题。\r\n线程安全示例（同步代码块）：',249,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'31','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(32,6,15,NULL,'第15段','class TicketSale implements Runnable {\r\n    private int ticket = 100;\r\n    private Object lock = new Object(); // 锁对象\r\n    @Override\r\n    public void run() {\r\n        while (true) {\r\n            synchronized (lock) { // 同步代码块，保证原子性\r\n                if (ticket > 0) {\r\n                    System.out.println(Thread.currentThread().getName() + \"售出第\" + ticket + \"张票\");\r\n                    ticket--;\r\n                    try {\r\n                        Thread.sleep(50);\r\n                    } catch (InterruptedException e) {\r\n                        e.printStackTrace();\r\n                    }\r\n                } else {\r\n                    break;\r\n                }\r\n            }\r\n        }\r\n    }\r\n}\r\n八、注解与反射（约 300 字）\r\n8.1 注解\r\n注解（Annotation）用于修饰类、方法、变量，提供元数据信息，常用内置注解：\r\n◦ @Override：标识方法重写；\r\n◦ @Deprecated：标识方法已过时；\r\n◦ @SuppressWarnings：抑制编译器警告。\r\n自定义注解示例：\r\n// 定义注解\r\n@Retention(RetentionPolicy.RUNTIME) // 注解保留到运行时\r\n@Target(ElementType.METHOD) // 注解作用于方法\r\npublic @interface MyAnnotation {',246,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'32','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(33,6,16,NULL,'第16段','    String value() default \"\"; // 注解属性\r\n}\r\n// 使用注解\r\npublic class Test {\r\n    @MyAnnotation(\"测试方法\")\r\n    public void test() {\r\n        System.out.println(\"注解测试\");\r\n    }\r\n}\r\n8.2 反射\r\n反射（Reflection）允许程序在运行时获取类的信息（属性、方法、构造器）并操作，核心类\r\n为Class。\r\n示例（通过反射调用方法）：\r\npublic class Test {\r\n    public void sayHello(String name) {\r\n        System.out.println(\"Hello \" + name);\r\n    }\r\n    public static void main(String[] args) throws Exception {\r\n        // 获取Class对象\r\n        Class;\r\n        // 创建对象\r\n        Object obj = clazz.newInstance();\r\n        // 获取方法（参数：方法名、参数类型）\r\n        Method method = clazz.getMethod(\"sayHello\", String.class);\r\n        // 调用方法（参数：对象、方法参数）\r\n        method.invoke(obj, \"Java\"); // 输出：Hello Java\r\n    }\r\n}\r\n九、Java 框架简介（约 200 字）\r\nJava 主流框架用于简化企业级开发：\r\n◦ Spring：核心是 IoC（控制反转）和 AOP（面向切面编程），提供依赖注入、事务管理等功能，是企\r\n业级开发的基石；\r\n◦ Spring Boot：基于 Spring，简化配置，实现 “开箱即用”，降低框架使用门槛；\r\n◦ MyBatis：持久层框架，简化 JDBC 操作，通过 XML 或注解映射数据库操作；\r\n◦ Spring MVC：Web 层框架，实现 MVC 设计模式，处理请求和响应；',241,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'33','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(34,6,17,NULL,'第17段','◦ Spring Cloud：微服务架构框架，提供服务注册发现、负载均衡、熔断等功能。\r\n这些框架相互配合，形成了 Java EE 开发的主流技术栈（SSM：Spring+Spring MVC+MyBatis，\r\nSpring Boot+Spring Cloud）。\r\n（注：文档部分内容可能由 AI 生成）',38,NULL,'SUCCESS','doubao-embedding-vision-251215',7,'34','2026-04-17 17:53:26','2026-04-17 11:40:59','2026-04-17 11:40:59'),(35,7,1,1,'第1页 · 第1段 · Java 核心知识全面梳理','Java 核心知识全面梳理\r\n一、Java 语言概述（约 500 字）\r\n1.1 语言简介\r\nJava 是由 Sun Microsystems（后被 Oracle 收购）于 1995 年推出的面向对象编程语言，其设计理念是\r\n “一次编写，到处运行（Write Once, Run Anywhere, WORA）”。核心优势在于跨平台性，通过 Java\r\n 虚拟机（JVM）实现 ——Java 源代码编译为字节码（.class 文件），再由不同平台的 JVM 解释执行，\r\n无需修改代码即可在 Windows、Linux、macOS 等系统运行。\r\n1.2 主要特点\r\n◦ 面向对象：封装、继承、多态三大特性，符合现实世界建模逻辑；\r\n◦ 跨平台：依赖 JVM 屏蔽底层系统差异，字节码具备平台无关性；\r\n◦ 安全性：内置安全机制，避免指针直接操作，防止内存泄露和恶意攻击；\r\n◦ 健壮性：强类型检查、异常处理机制，提升程序稳定性；\r\n◦ 多线程：原生支持多线程编程，适合并发场景开发。\r\n1.3 应用场景\r\nJava 广泛应用于企业级开发（Spring、MyBatis 框架）、移动开发（Android 应用）、大数据处理（-\r\nHadoop 生态）、中间件开发（Tomcat、Nacos）等领域，是当前最主流的编程语言之一。\r\n二、Java 基础语法（约 800 字）\r\n2.1 数据类型\r\nJava 数据类型分为基本类型和引用类型，其中基本类型共 8 种：\r\n类型 占用空间 取值范围',161,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'35','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(36,7,2,2,'第2页 · 第1段 · byte 1 字节 -128 ~ 127','byte 1 字节 -128 ~ 127\r\nshort 2 字节 -32768 ~ 32767\r\nint 4 字节 -2³¹ ~ 2³¹-1\r\nlong 8 字节 -2v³ ~ 2v³-1\r\nfloat 4 字节 单精度浮点数，约 ±3.4e38\r\ndouble 8 字节 双精度浮点数，约 ±1.8e308\r\nchar 2 字节 Unicode 字符（0 ~ 65535）\r\nboolean 1 字节 true/false\r\n引用类型包括类、接口、数组、枚举等，本质是指向对象的内存地址。\r\n2.2 变量与常量\r\n◦ 变量：需声明数据类型，语法为类型 变量名 = 初始值;，如int age = 20;；\r\n◦ 常量：用final修饰，一旦赋值不可修改，语法为final 类型 常量名 = 值;，如final double PI = 3.\r\n14159;（常量名通常大写）。\r\n2.3 运算符\r\n◦ 算术运算符：+-*/%++--（注意++前置自增与后置自增的区别）；\r\n◦ 关系运算符：`==、!=、>、<、>=、返回 boolean 类型；\r\n◦ 逻辑运算符：&&（短路与）、||（短路或）、!（非）；\r\n◦ 赋值运算符：=+=-=*=/=等；\r\n◦ 三元运算符：条件表达式 ? 表达式1 : 表达式2，如int max = a > b ? a : b;。\r\n2.4 流程控制\r\n2.4.1 条件语句',153,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'36','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(37,7,3,3,'第3页 · 第1段 · // if-else语句','// if-else语句\r\nif (age >= 18) {\r\n    System.out.println(\"成年人\");\r\n} else if (age >= 6) {\r\n    System.out.println(\"青少年\");\r\n} else {\r\n    System.out.println(\"儿童\");\r\n}\r\n// switch语句（JDK7+支持String类型）\r\nswitch (season) {\r\n    case \"春季\":\r\n        System.out.println(\"3-5月\");\r\n        break;\r\n    case \"夏季\":\r\n        System.out.println(\"6-8月\");\r\n        break;\r\n    default:\r\n        System.out.println(\"未知季节\");\r\n}\r\n2.4.2 循环语句\r\n// for循环\r\nfor (int i = 0; i  i++) {\r\n    System.out.println(i); // 输出0-9\r\n}\r\n// while循环\r\nint j = 0;\r\nwhile (j 0) {\r\n    System.out.println(j);\r\n    j++;\r\n}\r\n// do-while循环（至少执行一次）\r\nint k = 0;\r\ndo {\r\n    System.out.println(k);\r\n    k++;\r\n} while (k < 10);',167,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'37','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(38,7,4,4,'第4页 · 第1段 · 2.5 数组','2.5 数组\r\n数组是存储同一类型数据的固定长度容器，声明与初始化方式：\r\n// 声明并初始化\r\nint[] arr1 = {1, 2, 3};\r\n// 指定长度初始化\r\nint[] arr2 = new int[3];\r\narr2[0] = 1;\r\narr2[1] = 2;\r\narr2[2] = 3;\r\n// 遍历数组（增强for循环）\r\nfor (int num : arr1) {\r\n    System.out.println(num);\r\n}\r\n三、面向对象编程（约 1000 字）\r\n3.1 核心概念\r\n面向对象编程（OOP）以 “对象” 为核心，将数据和行为封装为一个整体，通过继承和多态实现代码\r\n复用和扩展。\r\n3.2 类与对象\r\n◦ 类：对象的模板，定义对象的属性（成员变量）和行为（成员方法）；\r\n◦ 对象：类的实例化结果，通过new关键字创建。\r\n示例代码：\r\n// 定义Person类\r\nclass Person {\r\n    // 成员变量（属性）\r\n    String name;\r\n    int age;\r\n    // 成员方法（行为）',122,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'38','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(39,7,5,5,'第5页 · 第1段 ·     }','    public void eat() {\r\n        System.out.println(name + \"正在吃饭\");\r\n    }\r\n    public void sleep() {\r\n        System.out.println(name + \"正在睡觉\");\r\n    }\r\n}\r\n// 创建对象并使用\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        Person person = new Person();\r\n        person.name = \"张三\";\r\n        person.age = 25;\r\n        person.eat(); // 输出：张三正在吃饭\r\n        person.sleep(); // 输出：张三正在睡觉\r\n    }\r\n}\r\n3.3 封装\r\n封装是将对象的属性私有化，通过公共的getter/setter方法控制访问，隐藏内部实现细节，提升安\r\n全性。\r\n示例代码：\r\nclass Person {\r\n    // 私有成员变量（仅本类可访问）\r\n    private String name;\r\n    private int age;\r\n    // getter方法（获取属性值）\r\n    public String getName() {\r\n        return name;\r\n    }\r\n    // setter方法（设置属性值，可添加逻辑校验）\r\n    public void setName(String name) {\r\n        if (name != null && !name.isEmpty()) {\r\n            this.name = name;\r\n        } else {\r\n            System.out.println(\"姓名不能为空\");\r\n        }',219,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'39','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(40,7,6,6,'第6页 · 第1段 ·     }','    }\r\n    public int getAge() {\r\n        return age;\r\n    }\r\n    public void setAge(int age) {\r\n        if (age >= 0 && age  120) {\r\n            this.age = age;\r\n        } else {\r\n            System.out.println(\"年龄无效\");\r\n        }\r\n    }\r\n}\r\n3.4 继承\r\n继承允许子类继承父类的属性和方法，子类可扩展新功能或重写父类方法，关键字为extends。Java \r\n支持单继承（一个子类只能有一个父类），但可通过接口实现多继承效果。\r\n示例代码：\r\n// 父类\r\nclass Animal {\r\n    public void move() {\r\n        System.out.println(\"动物会移动\");\r\n    }\r\n}\r\n// 子类继承父类\r\nclass Dog extends Animal {\r\n    // 重写父类方法\r\n    @Override\r\n    public void move() {\r\n        System.out.println(\"狗会跑\");\r\n    }\r\n    // 子类扩展方法\r\n    public void bark() {\r\n        System.out.println(\"狗会叫\");\r\n    }\r\n}\r\n// 测试\r\npublic class Test {',173,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'40','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(41,7,7,7,'第7页 · 第1段 ·     public static void main(Stri','    public static void main(String[] args) {\r\n        Dog dog = new Dog();\r\n        dog.move(); // 输出：狗会跑（重写后）\r\n        dog.bark(); // 输出：狗会叫（扩展方法）\r\n    }\r\n}\r\n3.5 多态\r\n多态是指同一行为在不同对象上表现出不同形态，实现条件：\r\n1. 子类继承父类；\r\n2. 子类重写父类方法；\r\n3. 父类引用指向子类对象。\r\n示例代码：\r\nclass Animal {\r\n    public void sound() {\r\n        System.out.println(\"动物发出声音\");\r\n    }\r\n}\r\nclass Cat extends Animal {\r\n    @Override\r\n    public void sound() {\r\n        System.out.println(\"猫喵喵叫\");\r\n    }\r\n}\r\nclass Bird extends Animal {\r\n    @Override\r\n    public void sound() {\r\n        System.out.println(\"鸟叽叽叫\");\r\n    }\r\n}\r\npublic class Test {\r\n    public static void main(String[] args) {\r\n        Animal animal1 = new Cat();\r\n        Animal animal2 = new Bird();\r\n        animal1.sound(); // 输出：猫喵喵叫',187,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'41','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(42,7,8,8,'第8页 · 第1段 ·     }','        animal2.sound(); // 输出：鸟叽叽叫\r\n    }\r\n}\r\n3.6 接口与抽象类\r\n◦ 抽象类：用abstract修饰，包含抽象方法（无实现）和普通方法，不能实例化，需子类继承并实现抽\r\n象方法；\r\n◦ 接口：用interface修饰，仅包含抽象方法（JDK8 + 支持默认方法和静态方法），类通过-\r\nimplements实现接口，可多实现。\r\n示例（接口）：\r\ninterface Flyable {\r\n    void fly(); // 抽象方法\r\n}\r\nclass Bird implements Flyable {\r\n    @Override\r\n    public void fly() {\r\n        System.out.println(\"鸟展翅飞翔\");\r\n    }\r\n}\r\nclass Plane implements Flyable {\r\n    @Override\r\n    public void fly() {\r\n        System.out.println(\"飞机引擎驱动飞行\");\r\n    }\r\n}\r\n四、Java 核心类库（约 600 字）\r\n4.1 String 类\r\nString 是不可变字符序列，常用方法：',138,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'42','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(43,7,9,9,'第9页 · 第1段 · String str = \"Hello Java\";','String str = \"Hello Java\";\r\nSystem.out.println(str.length()); // 长度：9\r\nSystem.out.println(str.charAt(0)); // 获取索引0字符：\'H\'\r\nSystem.out.println(str.substring(6)); // 截取子串：\"Java\"\r\nSystem.out.println(str.equals(\"hello java\")); // 比较内容：false（区分大小写）\r\nSystem.out.println(str.toLowerCase()); // 转小写：\"hello java\"\r\nSystem.out.println(str.split(\" \")); // 分割字符串：[\"Hello\", \"Java\"]\r\n注意：String 不可变，每次修改都会创建新对象，频繁修改建议使用StringBuilder（非线程安全）\r\n或StringBuffer（线程安全）。\r\n4.2 包装类\r\n基本类型的包装类用于将基本类型转换为对象，支持装箱（基本类型→对象）和拆箱（对象→基本类\r\n型）：\r\n基本类型 包装类\r\nint Integer\r\nchar Character\r\ndouble Double\r\n示例：\r\n// 装箱\r\nInteger num1 = 10; // 自动装箱（等价于Integer.valueOf(10)）\r\n// 拆箱\r\nint num2 = num1; // 自动拆箱（等价于num1.intValue()）\r\n// 常用方法\r\nSystem.out.println(Integer.parseInt(\"123\")); // 字符串转int：123\r\nSystem.out.println(Integer.MAX_VALUE); // 最大值：2147483647\r\n4.3 日期时间类\r\nJDK8 + 推荐使用java.time包下的日期时间类（替代旧版Date和Calendar）：',216,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'43','2026-04-17 19:08:17','2026-04-17 19:07:39'