   if (age  > 120) {\r\n        throw new AgeException(\"年龄无效：\" + age);\r\n    }\r\n}\r\n六、IO 流（约 500 字）\r\nIO 流用于文件读写、数据传输，按流向分为输入流（InputStream/Reader）和输出流（-\r\nOutputStream/Writer），按处理单位分为字节流（处理二进制文件）和字符流（处理文本文件）。',187,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'48','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(49,7,15,14,'第14页 · 第1段 · 6.1 字节流示例（复制图片）','6.1 字节流示例（复制图片）\r\npublic static void copyImage() {\r\n    FileInputStream fis = null;\r\n    FileOutputStream fos = null;\r\n    try {\r\n        // 输入流（读取源文件）\r\n        fis = new FileInputStream(\"source.jpg\");\r\n        // 输出流（写入目标文件）\r\n        fos = new FileOutputStream(\"target.jpg\");\r\n        byte[] buffer = new byte[1024]; // 缓冲区\r\n        int len;\r\n        // 读取数据并写入\r\n        while ((len = fis.read(buffer)) != -1) {\r\n            fos.write(buffer, 0, len);\r\n        }\r\n        System.out.println(\"图片复制成功\");\r\n    } catch (IOException e) {\r\n        e.printStackTrace();\r\n    } finally {\r\n        // 关闭流（释放资源）\r\n        try {\r\n            if (fis != null) fis.close();\r\n            if (fos != null) fos.close();\r\n        } catch (IOException e) {\r\n            e.printStackTrace();\r\n        }\r\n    }\r\n}\r\n6.2 字符流示例（读写文本文件）\r\npublic static void readTextFile() {\r\n    FileReader fr = null;',218,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'49','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(50,7,16,14,'第14页 · 第2段 ·     try {','    BufferedReader br = null; // 缓冲字符流，提高效率\r\n    try {\r\n        fr = new FileReader(\"test.txt\");\r\n        br = new BufferedReader(fr);',33,NULL,'SUCCESS','doubao-embedding-vision-251215',9,'50','2026-04-17 19:08:17','2026-04-17 19:07:39','2026-04-17 19:07:39'),(51,7,17,15,'第15页 · 第1段 ·         // 按行读取文本','        String line;\r\n        // 按行读取文本\r\n        while ((line = br.readLine()) != null) {\r\n            System.out.println(line);\r\n        }\r\n    } catch (IOException e) {\r\n      