INSERT INTO `question_item` VALUES (1,1,'SINGLE','根据资料内容，下列哪一项最符合核心主题？','事务与并发控制','前端组件样式设计','云服务器部署监控','图片识别算法优化','A','资料内容重点围绕事务特性、并发控制与调度正确性展开。','??????? ???',3,5,1,'2026-04-16 15:52:20','2026-04-16 15:52:20'),(2,1,'JUDGE','可串行化调度通常被视为事务并发执行正确性的重要标准。','正确','错误',NULL,NULL,'正确','资料中明确提到可串行化调度是正确性的重要标准。','??????? ???',3,5,2,'2026-04-16 15:52:20','2026-04-16 15:52:20'),(3,1,'SHORT_ANSWER','请简要写出资料中提到的一个核心知识点，并结合自己的理解说明其作用。',NULL,NULL,NULL,NULL,'开放题','可从事务四大特性、并发控制目标、读异常等角度作答。','??????? ???',3,10,3,'2026-04-16 15:52:20','2026-04-16 15:52:20'),(4,1,'SINGLE','以下哪项最可能属于资料中提到的并发读写问题？','脏读','死循环','内存泄漏','缓存穿透','A','资料中列举的典型并发异常包括脏读、不可重复读和幻读。','??????? ???',3,5,4,'2026-04-16 15:52:20','2026-04-16 15:52:20'),(5,1,'SHORT_ANSWER','结合以下资料摘要回答：\"????????????????????????????????????,??????????????????????????????????\"，请写出你的复习建议。',NULL,NULL,NULL,NULL,'开放题','建议从核心定义、场景分析、易错点辨析三个角度组织答案。','??????? ???',3,10,5,'2026-04-16 15:52:20','2026-04-16 15:52:20'),(6,2,'SINGLE','下列关于局域网（LAN）的说法，正确的是哪一项？','覆盖范围通常为跨国甚至全球','主要用于连接多个城市级网络','覆盖范围一般不超过10km，常见于校园网和企业园区网','必须依赖卫星作为主要传输介质','C','资料指出，局域网（LAN）覆盖范围≤10km，典型场景包括企业园区网和校园网，常采用以太网技术。','网络分类与局域网特征',3,5,1,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(7,2,'SINGLE','在 OSI 七层参考模型中，负责路由选择和地址分配的是哪一层？','数据链路层','网络层','传输层','应用层','B','OSI 模型中，网络层负责路由选择和地址分配，是实现网络间转发的关键层。','OSI七层模型',3,5,2,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(8,2,'JUDGE','TCP 是一种无连接、低延迟但不保证可靠性的传输层协议。','正确','错误',NULL,NULL,'错误','无连接、低延迟、不保证可靠性描述的是 UDP；TCP 提供可靠传输，并通过三次握手建立连接。','TCP与UDP对比',3,5,3,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(9,2,'SINGLE','下列哪一项是 IPv6 地址的典型表示形式？','192.168.1.1','255.255.255.0','www.baidu.com','2001:0db8:85a3:0000:0000:8a2e:0370:7334','D','IPv6 为 128 位地址，采用冒分十六进制表示。A 是 IPv4 地址，B 是子网掩码，C 是域名。','IPv4与IPv6地址表示',3,5,4,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(10,2,'SINGLE','下列关于动态路由协议的说法，正确的是哪一项？','OSPF 属于距离矢量协议','BGP 主要用于自治系统间路由','RIP 属于链路状态协议','静态路由能够自动更新路由表','B','资料中指出，RIP 是距离矢量协议，OSPF 是链路状态协议，BGP 是自治系统间路由协议；静态路由需要手动配置。','路由技术与常见协议',3,5,5,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(11,2,'SINGLE','HTTP/3 相比 HTTP/2 的突出特点是：','基于 TCP，实现串行请求传输','采用明文传输以提升速度','基于 QUIC（UDP 封装），可消除传输层队头阻塞','只能用于文件上传，不能用于网页访问','C','HTTP/3 基于 QUIC 协议（UDP 封装），能够消除传输层队头阻塞，并支持 0-RTT/1-RTT 握手和无缝网络切换。','HTTP协议演进',3,5,6,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(12,2,'JUDGE','DNS 的主要作用是将域名解析为 IP 地址，并且支持递归查询和迭代查询。','正确','错误',NULL,NULL,'正确','资料明确说明，DNS 是域名系统，用于将域名解析为 IP 地址，同时支持递归查询和迭代查询。','DNS协议功能',3,5,7,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(13,2,'SINGLE','下列哪一项最符合零信任架构的核心理念？','内网用户默认可信，无需反复验证','只要连接加密即可完全安全','永不信任，始终验证，基于最小权限进行访问控制','仅在发生攻击后再进行权限审查','C','零信任架构强调“永不信任，始终验证”，并基于最小权限原则对每个访问请求进行身份认证和权限校验。','零信任安全架构',3,5,8,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(14,2,'SHORT_ANSWER','简述物联网“端-边-云”架构的三个组成部分及其各自作用。',NULL,NULL,NULL,NULL,'端包括传感器、智能设备等，负责数据采集与执行；边包括边缘网关、边缘计算节点，负责本地处理、降低时延；云包括数据中心、AI模型库等，负责集中存储、分析和智能决策。','资料指出，“端-边-云”架构由终端、边缘节点和云端平台组成。终端负责感知和采集数据，边缘侧负责本地计算与快速响应，云端负责大规模数据处理和智能协同。','物联网端边云架构',3,5,9,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(15,2,'SHORT_ANSWER','为什么在视频通话、在线游戏等场景中常优先选择 UDP？请结合协议特点简要说明。',NULL,NULL,NULL,NULL,'因为 UDP 无连接、时延低、传输效率高，虽然不保证可靠性，但更适合对实时性要求高、可容忍少量丢包的场景，如视频通话和在线游戏。','资料中说明，UDP 的特点是无连接、低延迟、不保证可靠性，但传输效率高于 TCP，因此适用于实时通信、在线游戏等时延敏感场景。','UDP协议应用场景',3,5,10,'2026-04-16 16:39:19','2026-04-16 16:39:19'),(16,3,'SINGLE','在 TCP/IP 四层模型中，负责提供可靠传输并通过三次握手建立连接的协议属于哪一层？','网络接口层','网络层','传输层','应用层','C','TCP 属于传输层，负责端到端可靠传输，并通过三次握手建立连接、四次挥手释放连接。','TCP/IP 四层模型与 TCP 协议',3,5,1,'2026-04-16 16:50:18','2026-04-16 16:50:18'),(17,3,'JUDGE','HTTP/3 基于 QUIC 协议并采用 UDP 封装，能够消除传输层队头阻塞。','正确','错误',NULL,NULL,'正确','资料指出，HTTP/3 基于 QUIC 协议（UDP 封装），彻底消除传输层队头阻塞，并支持 0-RTT/1-RTT 握手和无缝网络切换。','HTTP/3 与 QUIC',3,5,2,'2026-04-16 16:50:18','2026-04-16 16:50:18'),(18,3,'SINGLE','以下哪一项最符合零信任架构的核心理念？','默认内网用户全部可信','永不信任，始终验证','只在登录时进行一次身份认证','所有访问请求均赋予最高权限','B','零信任架构强调“永不信任，始终验证”，并基于最小权限原则，对每个访问请求进行身份认证和权限校验。','零信任架构',3,5,3,'2026-04-16 16:50:18','2026-04-16 16:50:18'),(19,3,'SINGLE','在网络拓扑结构中，以下哪一种是当前局域网的主流架构？','总线型结构','环形结构','星型结构','全互连结构','C','资料中指出，星型结构以交换机、路由器等中心设备为核心，稳定性高、故障易排查，是当前局域网的主流架构。','网络拓扑结构',3,5,4,'2026-04-16 16:50:18','2026-04-16 16:50:18'),(20,3,'SHORT_ANSWER','简要说明 IPv4 与 IPv6 在地址长度和表示方式上的两个主要区别。',NULL,NULL,NULL,NULL,'IPv4 是 32 位地址，通常采用点分十进制表示；IPv6 是 128 位地址，通常采用冒分十六进制表示。','根据资料，IPv4 地址长度为 32 位，例如 192.168.1.1；IPv6 地址长度为 128 位，例如 2001:0db8:85a3:0000:0000:8a2e:0370:7334。二者主要区别体现在地址长度和表示方法上。','IPv4 与 IPv6',3,5,5,'2026-04-16 16:50:18','2026-04-16 16:50:18'),(27,5,'SINGLE','关于局域网（LAN）的描述，哪一项是正确的？','覆盖范围通常为 10-100km，主要用于连接多个城市','覆盖范围通常不超过 10km，常见于校园网和企业园区网','覆盖全球范围，互联网是其最大实例','主要依赖卫星进行长距离通信','B','资料指出，局域网（LAN）覆盖范围≤10km，典型场景包括企业园区网、校园网，常以以太网为核心技术。','网络分类与覆盖范围',3,5,1,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(28,5,'SINGLE','在 OSI 七层参考模型中，负责路由选择和地址分配的是哪一层？','数据链路层','传输层','网络层','应用层','C','OSI 模型中的网络层主要负责路由选择和地址分配，这是其核心职责。','OSI 七层模型',3,5,2,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(29,5,'SINGLE','下列关于 TCP 和 UDP 的说法，哪一项正确？','UDP 提供可靠传输，适合文件传输','TCP 无连接，时延一定低于 UDP','UDP 无连接、低延迟，适合视频通话等实时场景','TCP 不进行拥塞控制','C','资料指出，UDP 具有无连接、低延迟、不保证可靠性的特点，适用于视频通话、语音聊天、在线游戏等对时延敏感的场景。','传输层协议 TCP 与 UDP',3,5,3,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(30,5,'SINGLE','HTTP/3 的一个重要特点是：','基于 TCP，仍然存在传输层队头阻塞','基于 QUIC（UDP 封装），支持 0-RTT/1-RTT 握手','只能串行传输请求','不支持加密传输','B','资料明确提到，HTTP/3 基于 QUIC 协议（UDP 封装），支持 0-RTT/1-RTT 握手，并可消除传输层队头阻塞。','HTTP 协议演进',3,5,4,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(31,5,'SINGLE','下列哪一种路由协议属于自治系统间路由协议？','RIP','OSPF','ARP','BGP','D','资料中指出，BGP 属于自治系统间路由协议；RIP 是距离矢量协议，OSPF 是链路状态协议，ARP 用于地址解析。','动态路由协议',3,5,5,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(32,5,'JUDGE','IPv6 使用 128 位地址，采用冒分十六进制表示。','正确','错误',NULL,NULL,'正确','资料明确说明，IPv6 为 128 位地址，表示方式为冒分十六进制。','IPv4 与 IPv6',3,5,6,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(33,5,'JUDGE','零信任架构的核心理念是“永不信任，始终验证”，并强调最小权限原则。','正确','错误',NULL,NULL,'正确','资料中对零信任架构的定义正是“永不信任，始终验证”，并基于最小权限原则进行访问控制。','零信任安全架构',3,5,7,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(34,5,'SHORT_ANSWER','请简要说明 DNS 的主要作用，并写出一种资料中提到的 DNS 安全增强方式。',NULL,NULL,NULL,NULL,'DNS 的主要作用是将域名解析为 IP 地址。资料中提到的 DNS 安全增强方式是 DNS-over-HTTPS（DoH）。','DNS 是域名系统，负责把用户易记的域名转换成网络通信所需的 IP 地址。资料指出，2026 年已广泛部署 DNS-over-HTTPS（DoH）协议，以提升解析安全性。','DNS 协议与安全增强',3,10,8,'2026-04-16 20:58:35','2026-04-16 20:58:35'),(35,6,'SINGLE','Java 实现“跨平台”的关键机制是下面哪一项？','通过不同平台的 JVM 执行字节码','所有系统都直接运行同一份源代码且无需编译','Java 程序只能运行在 Windows 系统上','通过数据库驱动实现平台兼容','A','Java 源代码先编译成字节码，再由不同平台上的 JVM 解释执行，因此实现跨平台。','Java语言概述-跨平台与JVM',3,5,1,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(36,6,'SINGLE','下列哪个数据类型在 Java 中占用 8 字节？','int','short','long','char','C','资料中指出 long 占用 8 字节；int 占 4 字节，short 占 2 字节，char 占 2 字节。','Java基础语法-基本数据类型',3,5,2,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(37,6,'JUDGE','在 Java 中，使用 final 修饰的常量一旦赋值后通常不能再修改。','正确','错误',NULL,NULL,'正确','资料明确说明：常量用 final 修饰，一旦赋值不可修改。','Java基础语法-变量与常量',3,5,3,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(38,6,'SINGLE','关于 do-while 循环的特点，下列说法正确的是哪一项？','可能一次也不执行','至少执行一次','只能用于数组遍历','必须与 switch 一起使用','B','do-while 先执行循环体，再判断条件，因此至少会执行一次。','Java基础语法-流程控制',3,5,4,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(39,6,'SINGLE','在面向对象特性中，将属性私有化并通过 getter/setter 控制访问，这体现的是？','继承','多态','封装','重载','C','封装就是隐藏内部实现细节，将属性私有化，并通过公共方法控制访问。','面向对象编程-封装',3,5,5,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(40,6,'JUDGE','Java 支持一个子类同时继承多个父类，这是 Java 继承机制的重要特点。','正确','错误',NULL,NULL,'错误','资料指出 Java 只支持单继承，即一个子类只能有一个父类，但可通过接口实现多继承效果。','面向对象编程-继承',3,5,6,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(41,6,'SINGLE','下列关于 String 类的说法，正确的是哪一项？','String 是可变字符序列','String 频繁修改时优先使用 String','String 不可变，频繁修改建议使用 StringBuilder','String 只能存储英文，不能存储中文','C','资料中说明 String 是不可变字符序列，每次修改都会创建新对象，频繁修改建议使用 StringBuilder 或 StringBuffer。','Java核心类库-String类',3,5,7,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(42,6,'SINGLE','下列集合实现类中，哪一个具有“元素无序且不可重复”的特点？','ArrayList','LinkedList','HashSet','HashMap','C','HashSet 属于 Set 接口实现类，特点是无序、元素不可重复。','Java核心类库-集合框架Set',3,5,8,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(43,6,'JUDGE','在 try-catch-finally 结构中，finally 代码块无论是否发生异常，通常都会执行。','正确','错误',NULL,NULL,'正确','资料说明 finally 无论是否异常都会执行，常用于资源释放。','异常处理-try-catch-finally',3,5,9,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(44,6,'SHORT_ANSWER','简要说明 Java 中创建线程的两种常见方式，并各写出一种对应的类或接口名称。',NULL,NULL,NULL,NULL,'常见方式有两种：1. 继承 Thread 类；2. 实现 Runnable 接口。','资料在多线程部分列出了继承 Thread 类和实现 Runnable 接口两种常见创建线程方式，另外还提到实现 Callable 接口可获得返回值。','多线程-线程创建方式',3,5,10,'2026-04-17 11:42:53','2026-04-17 11:42:53'),(45,7,'SINGLE','Java 之所以能够实现“跨平台”，主要依赖于什么？','JDK','JVM','JRE','IDE','B','Java 源代码会先编译为字节码，再由不同平台上的 JVM 解释执行，因此实现跨平台。','Java语言概述-跨平台机制',2,5,1,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(46,7,'SINGLE','下列哪一个是 Java 的基本数据类型？','String','Array','int','Integer[]','C','Java 的 8 种基本数据类型中包括 int；String、Array、Integer[] 都不属于基本类型。','Java基础语法-数据类型',2,5,2,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(47,7,'JUDGE','在 Java 中，final 修饰的常量一旦赋值后通常不能再修改。','正确','错误',NULL,NULL,'正确','资料中指出：常量用 final 修饰，一旦赋值不可修改。','Java基础语法-变量与常量',2,5,3,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(48,7,'SINGLE','关于 Java 面向对象特性的说法，哪一项是正确的？','Java 支持多个类继承一个子类','Java 只支持多继承，不支持单继承','Java 支持单继承，但可通过接口实现多继承效果','子类不能重写父类方法','C','资料明确说明：Java 支持单继承，一个子类只能有一个父类，但可通过接口实现多继承效果。','面向对象编程-继承',2,5,4,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(49,7,'JUDGE','String 是可变字符序列，因此频繁修改字符串时优先使用 String。','正确','错误',NULL,NULL,'错误','String 是不可变字符序列，频繁修改时建议使用 StringBuilder 或 StringBuffer。','Java核心类库-String类',2,5,5,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(50,7,'SINGLE','下列关于集合的描述，哪一项是正确的？','List 中元素无序且不可重复','Set 中元素有序且可重复','Map 的 key 可以重复，value 不可重复','HashSet 中重复元素添加会失败','D','资料中指出：Set 不可重复，HashSet 示例中重复元素“张三”添加失败。','集合框架-Set接口',2,5,6,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(51,7,'SHORT_ANSWER','请简要写出 Java 中实现多态的三个条件。',NULL,NULL,NULL,NULL,'1. 子类继承父类；2. 子类重写父类方法；3. 父类引用指向子类对象。','资料在“3.5 多态”中明确给出了实现多态的三个条件，答出这三点即可。','面向对象编程-多态',2,5,7,'2026-04-17 16:45:18','2026-04-17 16:45:18'),(62,9,'SINGLE','根据资料，Dockerfile 中必须作为第一条指令的是哪一项？','RUN','FROM','CMD','ENV','B','资料明确指出：FROM 用于指定基础镜像，必须是第一条指令。','Dockerfile 常用指令',2,5,1,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(63,9,'SINGLE','下列哪一项用于设置 Dockerfile 的工作目录？','WORKDIR','EXPOSE','ENTRYPOINT','ADDUSER','A','资料中列出 WORKDIR 的作用是设置工作目录。','Dockerfile 常用指令',2,5,2,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(64,9,'SINGLE','根据资料，哪条 Dockerfile 指令用于声明容器监听的端口？','COPY','RUN','EXPOSE','CMD','C','资料中写明 EXPOSE 的作用是声明容器监听的端口。','Dockerfile 常用指令',2,5,3,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(65,9,'SINGLE','以下哪一项是资料中给出的 Dockerfile 最佳实践？','优先使用 latest 标签','尽量增加镜像层数','安装软件后保留缓存','使用具体的基础镜像版本标签而非 latest','D','资料建议使用具体的基础镜像版本标签而非 latest。','Dockerfile 最佳实践',2,5,4,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(66,9,'SINGLE','根据学习阶段划分，第一阶段“基础入门”的时间范围是多久？','0-2 周','2-4 周','4-6 周','6-10 周','A','资料中明确写出第一阶段：基础入门（0-2 周）。','Docker 学习路线图',2,5,5,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(67,9,'SINGLE','根据资料，Docker 的三大核心概念不包括下列哪一项？','镜像','容器','仓库','集群','D','资料指出 Docker 三大核心概念为镜像、容器、仓库，不包括集群。','Docker 基础概念',2,5,6,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(68,9,'SINGLE','根据认证指南，Docker Certified Associate（DCA）考试题目数是多少？','45 道','50 道','55 道','60 道','C','资料中写明 DCA 考试题目数为 55 道。','Docker 认证指南',2,5,7,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(69,9,'SINGLE','根据资料，DCA 考试的时间限制是多久？','60 分钟','90 分钟','120 分钟','180 分钟','B','认证指南中明确写出时间限制为 90 分钟。','Docker 认证指南',2,5,8,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(70,9,'SINGLE','根据容器与虚拟机的对比，容器的启动时间通常是哪个级别？','小时级','分钟级','秒级','天级','C','资料指出容器启动时间为秒级，而虚拟机为分钟级。','容器与虚拟机区别',2,5,9,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(71,9,'SINGLE','根据资料，Docker 官方镜像库的网址是哪个？','https://hub.docker.com/','https://docker.io/images','https://github.com/docker/images','https://docs.docker.com/hub/library','A','相关资源中明确列出 Docker 官方镜像库：https://hub.docker.com/。','Docker 相关资源',2,5,10,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(72,9,'JUDGE','本书采用的是 CC BY-NC-SA 4.0 许可证。','正确','错误',NULL,NULL,'正确','资料中“许可证”部分明确写明本书采用 CC BY-NC-SA 4.0 许可证。','许可证信息',2,5,11,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(73,9,'JUDGE','资料建议在 Dockerfile 中优先使用 latest 作为基础镜像标签。','正确','错误',NULL,NULL,'错误','资料的最佳实践建议是使用具体的基础镜像版本标签，而非 latest。','Dockerfile 最佳实践',2,5,12,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(74,9,'JUDGE','根据资料，.dockerignore 文件可用于排除不必要的文件。','正确','错误',NULL,NULL,'正确','资料在最佳实践建议中明确提出使用 .dockerignore 文件排除不必要的文件。','Dockerfile 最佳实践',2,5,13,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(75,9,'JUDGE','根据学习路线图，Docker Compose 位于 Dockerfile 和镜像构建之前学习。','正确','错误',NULL,NULL,'错误','知识点依赖关系显示先学习 Dockerfile 和镜像构建，再到数据管理、网络配置、Docker Compose。','知识点依赖关系',2,5,14,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(76,9,'JUDGE','根据资料，容器通常共享内核，包含应用和依赖。','正确','错误',NULL,NULL,'正确','常见面试题答案要点中指出：容器共享内核，包含应用和依赖。','容器与虚拟机区别',2,5,15,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(77,9,'JUDGE','根据资料，DCA 考试有效期为 5 年。','正确','错误',NULL,NULL,'错误','认证指南中写明 DCA 有效期为 3 年，不是 5 年。','Docker 认证指南',2,5,16,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(78,9,'JUDGE','根据资料，Kubernetes 基础阶段包含 Pod、Service、Deployment 等内容。','正确','错误',NULL,NULL,'正确','知识点依赖关系中“Kubernetes 基础”包含 Pod / Service / Deployment。','知识点依赖关系',2,5,17,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(79,9,'SHORT_ANSWER','根据资料，简要写出 Dockerfile 中任意四个常用指令名称。',NULL,NULL,NULL,NULL,'示例：FROM、RUN、WORKDIR、COPY。也可回答 ADD、EXPOSE、ENV、ENTRYPOINT、CMD 中的任意四个。','资料列出的常用指令包括 FROM、RUN、WORKDIR、COPY/ADD、EXPOSE、ENV、ENTRYPOINT、CMD。','Dockerfile 常用指令',2,10,18,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(80,9,'SHORT_ANSWER','根据资料，简要概括容器相比虚拟机的两个特点。',NULL,NULL,NULL,NULL,'示例：容器共享内核、更轻量；启动时间是秒级；性能开销更低；密度更高。答出其中两点即可。','资料对比指出：容器共享内核，MB 级，秒级启动，进程级隔离，性能开销低，总结为更轻量、更快、密度更高。','容器与虚拟机区别',2,10,19,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(81,9,'SHORT_ANSWER','根据资料，列出 DCA 考试内容比例中的任意三个类别。',NULL,NULL,NULL,NULL,'示例：镜像和仓库、容器运行、网络。也可回答存储、编排、安全、日志中的任意三项。','认证指南给出的考试内容比例包括：镜像和仓库、容器运行、网络、存储、编排、安全、日志。','Docker 认证指南',2,10,20,'2026-04-17 20:08:55','2026-04-17 20:08:55'),(82,10,'SINGLE','Docker 的三大核心概念不包括哪一项？','镜像','容器','仓库','集群','D','资料中明确指出 Docker 的三大核心概念是镜像、容器、仓库，不包括集群。','Docker 三大核心概念',1,5,1,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(83,10,'SINGLE','执行交互式容器进入容器内部与系统交互的命令是哪个？','docker build -t ubuntu bash','docker run -it ubuntu bash','docker exec ubuntu -it bash','docker start -it ubuntu bash','B','快速上手步骤中给出的交互式容器命令是 docker run -it ubuntu bash。','交互式容器命令',1,5,2,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(84,10,'SINGLE','Dockerfile 中必须作为第一条指令的是哪一个？','RUN','COPY','FROM','CMD','C','资料中说明 FROM 用于指定基础镜像，必须是第一条指令。','Dockerfile 指令 FROM',1,5,3,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(85,10,'SINGLE','下列哪项最符合 Dockerfile 的最佳实践？','始终使用 latest 标签','尽量增加镜像层数','安装软件后保留全部缓存','使用具体的基础镜像版本标签','D','最佳实践建议中明确提出应使用具体的基础镜像版本标签而非 latest。','Dockerfile 最佳实践',1,5,4,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(86,10,'SINGLE','下列哪种网络类型是默认的 Docker 网络驱动？','bridge','host','overlay','macvlan','A','资料中说明 Bridge 是默认网络驱动。','Docker 网络类型',1,5,5,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(87,10,'SINGLE','更推荐在生产环境中使用的数据存储方式是哪一种？','Volume','Bind Mount','tmpfs','host 网络','A','资料中指出 Volume 由 Docker 管理，隔离性好，推荐在生产环境使用。','Volume 与 Bind Mount 区别',1,5,6,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(88,10,'SINGLE','关于 CMD 和 ENTRYPOINT 的说法，哪一项正确？','CMD 定义容器启动入口点，且运行时参数会追加','ENTRYPOINT 定义容器默认命令，运行时总会被完全覆盖','CMD 可被运行时命令覆盖，而 ENTRYPOINT 更适合定义可执行程序','CMD 与 ENTRYPOINT 作用完全相同','C','资料中说明 CMD 定义默认命令，可被覆盖；ENTRYPOINT 定义可执行程序，运行时参数追加而非覆盖。','CMD 与 ENTRYPOINT 区别',1,5,7,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(89,10,'SINGLE','对于 Docker Certified Associate (DCA) 考试，镜像和仓库部分的内容占比是多少？','10%','15%','20%','25%','C','认证指南中给出的 DCA 考试内容比例里，镜像和仓库占 20%。','DCA 考试内容比例',1,5,8,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(90,10,'JUDGE','容器通常共享内核，启动时间一般为秒级。','正确','错误',NULL,NULL,'正确','资料中对比说明容器共享内核，启动时间为秒级。','容器与虚拟机区别',1,5,9,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(91,10,'JUDGE','tmpfs 是持久化存储，容器重启后数据仍会保留。','正确','错误',NULL,NULL,'错误','资料中指出 tmpfs 是内存文件系统，不持久化，重启后数据会丢失。','tmpfs 特点',1,5,10,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(92,10,'JUDGE','避免以 root 身份运行容器应用属于安全和最佳实践建议之一。','正确','错误',NULL,NULL,'正确','资料中的最佳实践和安全建议均提到应避免以 root 身份运行容器应用，推荐使用非 root 用户。','容器安全最佳实践',1,5,11,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(93,10,'SHORT_ANSWER','简述 Docker 镜像的存储特点。',NULL,NULL,NULL,NULL,'镜像本质是只读的文件系统快照，采用分层存储结构。每一层是前一层的增量，常见由 RUN、COPY、ADD 等指令创建层。其存储方式可理解为多个只读层加一个可写层，层之间通过 diff 增量存储，从而节省空间、支持层共享并加快构建。','答题要点包括：只读文件系统快照、分层存储、增量层、多个只读层加可写层、节省空间、共享基础层、缓存加速构建。','Docker 镜像分层存储',1,5,12,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(94,10,'SHORT_ANSWER','简述提升 Docker 安全性的做法，至少写出四点。',NULL,NULL,NULL,NULL,'可从以下方面提升 Docker 安全性：1. 使用官方镜像或可信镜像源；2. 定期扫描漏洞；3. 做镜像签名验证；4. 生成和管理 SBOM；5. 以非 root 用户运行容器；6. 使用只读文件系统；7. 限制 Linux 能力；8. 使用 AppArmor 或 SELinux；9. 启用 TLS 认证 API；10. 不暴露 /var/run/docker.sock；11. 使用 Rootless 容器；12. 定期更新 Docker；13. 使用自定义网络隔离并限制出入站流量。','资料从镜像安全、容器运行、宿主机安全、网络安全四个方向给出措施，答出其中任意四点及以上即可。','Docker 安全实践',1,5,13,'2026-04-17 20:42:48','2026-04-17 20:42:48'),(95,11,'SINGLE','Docker 的三大核心概念不包括哪一项？','镜像','容器','仓库','集群','D','资料明确指出 Docker 的三大核心概念是镜像、容器、仓库，集群不属于三大核心概念。','Docker 三大核心概念',3,5,1,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(96,11,'SINGLE','Dockerfile 中必须作为第一条指令的是哪一项？','RUN','FROM','CMD','ENV','B','资料列出 Dockerfile 常用指令时说明，FROM 用于指定基础镜像，必须是第一条指令。','Dockerfile 指令 FROM',3,5,2,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(97,11,'SINGLE','哪条 Dockerfile 指令用于设置工作目录？','WORKDIR','COPY','EXPOSE','ENTRYPOINT','A','资料中明确说明 WORKDIR 的作用是设置工作目录。','Dockerfile 指令 WORKDIR',3,5,3,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(98,11,'SINGLE','为了减少最终镜像体积，推荐采用哪种做法？','始终使用 latest 标签','增加镜像层数','使用多阶段构建','全部以 root 身份运行','C','最佳实践建议中明确提出，使用多阶段构建可以减小最终镜像体积。','Dockerfile 最佳实践',3,5,4,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(99,11,'SINGLE','编写 Dockerfile 时，基础镜像标签的推荐做法是哪一项？','优先使用 latest','使用具体的版本标签','不写标签','随机选择标签','B','资料中的最佳实践建议明确指出，应使用具体的基础镜像版本标签而非 latest。','基础镜像版本管理',3,5,5,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(100,11,'SINGLE','关于 CMD 与 ENTRYPOINT 的区别，哪一项表述正确？','CMD 定义容器入口程序，且运行时参数只能追加','ENTRYPOINT 定义默认命令，运行时总会被完全覆盖','CMD 可在容器运行时被覆盖，ENTRYPOINT 的参数通常是追加','CMD 和 ENTRYPOINT 完全等价，没有区别','C','资料说明 CMD 定义默认命令，运行时可被覆盖；ENTRYPOINT 定义可执行程序，运行时参数追加而非覆盖。','CMD 与 ENTRYPOINT 区别',3,5,6,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(101,11,'SINGLE','默认的 Docker 网络类型是哪一项？','host','overlay','macvlan','bridge','D','资料在容器网络类型说明中标注 bridge 为默认网络类型。','Docker 网络类型',3,5,7,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(102,11,'SINGLE','哪种网络驱动使用宿主机网络栈，性能最优但隔离性最差？','bridge','host','overlay','none','B','资料指出 Host 网络使用宿主机网络栈，性能最优，但隔离性最差。','Host 网络驱动特性',3,5,8,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(103,11,'SINGLE','准备 Docker Certified Associate（DCA）认证时，哪组命令被列为重点掌握内容？','docker build / push / pull / tag','kubectl apply / get / logs / exec','systemctl start / stop / reload / status','git add / commit / push / rebase','A','资料在 DCA 准备建议中明确列出重点掌握命令，其中包括 docker build、push、pull、tag。','DCA 备考重点命令',3,5,9,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(104,11,'JUDGE','Docker 镜像的本质是只读的文件系统快照，并采用分层存储结构。','正确','错误',NULL,NULL,'正确','资料对镜像的说明中明确指出，镜像本质是只读的文件系统快照，且具有分层存储结构。','Docker 镜像本质与存储',3,5,10,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(105,11,'JUDGE','在 Dockerfile 中可以有多个 CMD 指令，并且它们都会在容器启动时依次执行。','正确','错误',NULL,NULL,'错误','资料明确说明可以有多个 CMD，但只有最后一个生效，并不会依次执行。','CMD 指令规则',3,5,11,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(106,11,'JUDGE','学习路径中的知识点依赖关系显示，应先掌握基础概念，再学习 Dockerfile 和镜像构建。','正确','错误',NULL,NULL,'正确','资料中的知识点依赖关系图显示，基础概念位于前置阶段，之后才进入 Dockerfile 和镜像构建。','Docker 学习路径依赖关系',3,5,12,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(107,11,'SHORT_ANSWER','简述容器与虚拟机的主要区别。',NULL,NULL,NULL,NULL,'容器共享内核，通常只包含应用和依赖，体积为 MB 级，启动时间为秒级，属于进程级隔离，性能开销低；虚拟机提供完整操作系统环境，体积为 GB 级，启动时间为分钟级，隔离级别为完全硬件隔离，性能开销更高。','资料从体积、启动时间、隔离级别和性能开销四个方面对容器与虚拟机进行了对比，结论是容器更轻量、更快、密度更高。','容器与虚拟机的区别',3,10,13,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(108,11,'SHORT_ANSWER','写出至少四条 Dockerfile 编写最佳实践。',NULL,NULL,NULL,NULL,'可写出以下任意四条或以上：使用具体的基础镜像版本标签而非 latest；最小化镜像层数并合并 RUN 指令；使用 .dockerignore 排除不必要文件；安装必要软件包后清理缓存；使用多阶段构建减小最终镜像体积；避免以 root 身份运行容器应用。','资料在 Dockerfile 最佳实践建议中列出了六条高价值建议，回答时写出其中至少四条即可。','Dockerfile 最佳实践',3,10,14,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(109,11,'SHORT_ANSWER','概述“5分钟运行第一个容器”的主要学习步骤。',NULL,NULL,NULL,NULL,'主要步骤包括：先根据操作系统完成 Docker 的安装与验证；快速体验构建镜像与启动容器的完整流程；执行 docker run -it ubuntu bash 进入交互式容器；理解镜像与仓库并学会拉取、使用和管理；学习编写 Dockerfile 创建自定义镜像。','资料给出了五分钟快速上手路径，涵盖安装验证、第一个容器、交互式容器、镜像与仓库、自定义镜像五个步骤。','Docker 快速上手流程',3,10,15,'2026-04-18 13:07:23','2026-04-18 13:07:23'),(110,12,'SINGLE','Dockerfile 中必须作为第一条出现的指令是哪个？','RUN','FROM','CMD','WORKDIR','B','FROM 用于指定基础镜像，资料明确说明它必须是第一条指令。','Dockerfile 常用指令',3,5,1,'2026-04-18 13:36:41','2026-04-18 13:36:41'),(111,12,'SINGLE','为了减小最终镜像体积，哪种做法最符合最佳实践？','始终使用 latest 标签','将所有调试工具都保留在运行镜像中','使用多阶段构建','默认以 root 身份运行容器应用','C','资料将多阶段构建列为减小最终镜像体积的重要最佳实践；其余选项都不符合推荐做法。','Dockerfile 最佳实践与镜像优化',3,5,2,'2026-04-18 13:36:41','2026-04-18 13:36:41'),(112,12,'SINGLE','关于 CMD 和 ENTRYPOINT 的区别，哪项说法正确？','CMD 定义可执行程序，运行时参数只会追加','ENTRYPOINT 会在容器运行时被完全覆盖，CMD 不会','CMD 定义容器默认命令，可在运行时被覆盖','ENTRYPOINT 和 CMD 完全等价，没有推荐配合用法','C','资料指出 CMD 用于定义容器默认命令，docker run 时可被覆盖；ENTRYPOINT 定义可执行程序，运行时参数通常是追加而非覆盖。','CMD 与 ENTRYPOINT 区别',3,5,3,'2026-04-18 13:36:41','2026-04-18 13:36:41'),(113,12,'SINGLE','哪种 Docker 网络驱动默认使用虚拟网桥，支持端口映射且隔离性较好？','host','overlay','none','bridge','D','资料说明 bridge 是默认网络驱动，基于虚拟网桥通信，支持端口映射，隔离性好、性能适中。','Docker 网络驱动',3,5,4,'2026-04-18 13:36:41','2026-04-18 13:36:41'),(114,12,'SINGLE','容器实现资源限制主要依靠哪种机制？','Namespace','Cgroup','Union FS','VXLAN','B','资料指出 Cgroup 用于资源限制，例如限制 CPU、内存、磁盘 I/O 和网络带宽；Namespace 主要负责资源隔离。','容器隔离与资源限制机制',3,5,5,'2026-04-18 13:36:41','2026-04-18 13:36:41'),(115,13,'SINGLE','Docker 的三大核心概念不包括下面哪一项？','镜像','容器','仓库','集群','D','资料明确给出 Docker 的三大核心概念为镜像、容器、仓库，不包括集群。','Docker 三大核心概念',3,5,1,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(116,13,'SINGLE','快速进入容器内部与系统交互的命令是哪个？','docker build -t ubuntu bash','docker run -it ubuntu bash','docker pull ubuntu bash','docker exec ubuntu bash','B','资料在“五分钟快速上手”中明确给出交互式容器示例命令为 docker run -it ubuntu bash。','交互式容器命令',3,5,2,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(117,13,'SINGLE','Dockerfile 中必须作为第一条指令的是哪一个？','RUN','WORKDIR','FROM','CMD','C','资料指出 FROM 用于指定基础镜像，必须是第一条指令。','Dockerfile 指令 FROM',3,5,3,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(118,13,'SINGLE','Dockerfile 中用于在镜像中执行命令、安装软件包等的指令是哪个？','RUN','ENV','EXPOSE','ENTRYPOINT','A','资料总结中说明 RUN 用于在镜像中执行命令，常用于安装软件包等。','Dockerfile 指令 RUN',3,5,4,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(119,13,'SINGLE','Dockerfile 中用于设置工作目录的指令是哪个？','COPY','WORKDIR','ARG','USER','B','资料明确指出 WORKDIR 的作用是设置工作目录。','Dockerfile 指令 WORKDIR',3,5,5,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(120,13,'SINGLE','Dockerfile 中用于声明容器监听端口的指令是哪个？','ENV','CMD','EXPOSE','ADD','C','资料中说明 EXPOSE 用于声明容器监听的端口。','Dockerfile 指令 EXPOSE',3,5,6,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(121,13,'SINGLE','Dockerfile 中用于设置环境变量的指令是哪个？','ENV','RUN','FROM','VOLUME','A','资料总结中明确 ENV 用于设置环境变量。','Dockerfile 指令 ENV',3,5,7,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(122,13,'SINGLE','关于 CMD 与 ENTRYPOINT 的说法，正确的是哪一项？','CMD 运行时参数只能追加不能覆盖','ENTRYPOINT 定义容器默认命令且总会被覆盖','CMD 定义默认命令，可在运行时被覆盖','ENTRYPOINT 和 CMD 不能配合使用','C','资料指出 CMD 用于定义容器默认命令，容器运行时可被覆盖；ENTRYPOINT 定义可执行程序，运行时参数通常为追加。','CMD 与 ENTRYPOINT 区别',3,5,8,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(123,13,'SINGLE','当 ENTRYPOINT 设置为 [\"python\", \"app.py\"]，CMD 设置为 [\"--port\", \"8000\"] 时，执行 docker run image --debug 的结果是什么？','只执行 --debug','执行 python app.py --debug','执行 python --port 8000 --debug','执行 app.py --port 8000','B','资料给出的推荐用法示例中明确说明，运行 docker run image --debug 会执行 python app.py --debug。','ENTRYPOINT 与 CMD 配合使用',3,5,9,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(124,13,'SINGLE','下列哪项属于构建高质量镜像的最佳实践？','始终使用 latest 标签','尽量增加镜像层数','使用具体的基础镜像版本标签','所有文件都打包进构建上下文','C','资料建议使用具体的基础镜像版本标签而非 latest，以提升可控性和稳定性。','Dockerfile 最佳实践',3,5,10,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(125,13,'SINGLE','为了最小化镜像层数，推荐采用哪种做法？','拆分更多 RUN 指令','合并 RUN 指令','尽量不用 Dockerfile','只使用 ADD 指令','B','资料明确提出应最小化镜像层数，做法之一是合并 RUN 指令。','镜像层优化',3,5,11,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(126,13,'SINGLE','为了排除不必要的文件进入构建上下文，应该使用哪个文件？','.gitignore','compose.yml','.dockerignore','Dockerfile.lock','C','资料中的最佳实践建议明确指出，使用 .dockerignore 文件排除不必要的文件。','.dockerignore 的作用',3,5,12,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(127,13,'SINGLE','安装必要软件包后，为减小镜像体积，推荐紧接着做什么？','增加一个 EXPOSE 指令','清理缓存','改用 latest 标签','添加更多环境变量','B','资料将“安装必要的软件包后清理缓存”列为最佳实践之一。','减小镜像体积的实践',3,5,13,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(128,13,'SINGLE','减小最终镜像体积的推荐方法是哪一个？','多阶段构建','重复使用 latest','使用 host 网络','增加容器数量','A','资料明确提出使用多阶段构建可以减小最终镜像体积。','多阶段构建',3,5,14,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(129,13,'SINGLE','从安全最佳实践角度，运行容器应用时应避免哪种方式？','使用具体版本标签','使用多阶段构建','以 root 身份运行','使用 .dockerignore','C','资料明确建议避免以 root 身份运行容器应用。','容器安全最佳实践',3,5,15,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(130,13,'SINGLE','关于 Docker 镜像存储特性，哪一项说法正确？','镜像是可写文件系统快照','镜像采用分层存储结构','每个镜像只能有一层','镜像层之间不会共享','B','资料说明镜像本质是只读的文件系统快照，并采用分层存储结构。','镜像分层存储',3,5,16,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(131,13,'SINGLE','下列哪组指令会创建镜像层？','RUN/COPY/ADD','EXPOSE/ENV/CMD','WORKDIR/USER/ARG','ENTRYPOINT/CMD/HEALTHCHECK','A','资料指出每一个 RUN、COPY、ADD 指令会创建一层。','镜像层创建规则',3,5,17,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(132,13,'SINGLE','默认的 Docker 网络类型是哪一个？','host','overlay','bridge','macvlan','C','资料在网络类型说明中标明 bridge 为默认网络类型。','Docker 网络类型',3,5,18,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(133,13,'SINGLE','哪种网络模式使用宿主机网络栈、性能最优但隔离性最差？','bridge','host','overlay','none','B','资料说明 Host 网络使用宿主机网络栈，性能最优，但隔离性最差。','Host 网络特点',3,5,19,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(134,13,'SINGLE','哪种网络驱动主要用于跨主机通信，并支持分布式场景？','overlay','host','none','bridge','A','资料指出 Overlay 用于跨主机通信，基于 VXLAN，支持分布式场景。','Overlay 网络特点',3,5,20,'2026-04-18 13:37:46','2026-04-18 13:37:46'),(135,14,'SINGLE','Dockerfile 中必须作为第一条出现的指令是哪个？','RUN','FROM','CMD','WORKDIR','B','FROM 用于指定基础镜像，并且必须是 Dockerfile 的第一条指令。','Dockerfile 常用指令',3,5,1,'2026-04-18 19:17:40','2026-04-18 19:17:40'),(136,14,'SINGLE','为了减小最终镜像体积，哪种做法最符合推荐实践？','始终使用 latest 标签','尽量增加 RUN 指令层数','使用多阶段构建','将所有文件都打包进镜像','C','最佳实践明确提到使用多阶段构建可以减小最终镜像体积；同时还建议最小化镜像层数、排除不必要文件，而不是增加层数或全部打包。','Dockerfile 最佳实践',3,5,2,'2026-04-18 19:17:40','2026-04-18 19:17:40'),(137,14,'SINGLE','关于 CMD 和 ENTRYPOINT 的区别，下列说法正确的是哪一项？','CMD 定义可执行程序，且运行时参数只能追加','ENTRYPOINT 定义默认命令，运行时总会被完全覆盖','CMD 运行时可被覆盖，而 ENTRYPOINT 更适合作为固定入口程序','CMD 和 ENTRYPOINT 完全等价，只是写法不同','C','CMD 定义容器默认命令，运行时可被覆盖；ENTRYPOINT 定义容器启动时的可执行程序，运行时参数通常是追加而非覆盖，二者常配合使用。','CMD 与 ENTRYPOINT 的区别',3,5,3,'2026-04-18 19:17:40','2026-04-18 19:17:40'),(138,14,'SINGLE','哪一种 Docker 网络类型默认使用虚拟网桥，并支持端口映射？','bridge','host','none','macvlan','A','bridge 是默认网络类型，使用虚拟网桥实现容器间通信，并支持端口映射。','Docker 网络类型',3,5,4,'2026-04-18 19:17:40','2026-04-18 19:17:40'),(139,14,'SINGLE','交互式进入容器内部与系统交互的命令示例是哪一个？','docker build -t ubuntu bash','docker pull -it ubuntu bash','docker run -it ubuntu bash','docker exec -d ubuntu bash','C','快速上手步骤中给出的交互式容器示例命令是 docker run -it ubuntu bash，用于进入容器内部进行交互。','Docker 容器交互式运行',3,5,5,'2026-04-18 19:17:40','2026-04-18 19:17:40'),(140,15,'SINGLE','下列关于 IPv4 与 IPv6 的说法，正确的是哪一项？','IPv4 为 128 位地址，采用冒分十六进制表示','IPv6 为 32 位地址，采用点分十进制表示','IPv4 地址资源已枯竭，NAT 技术可用于缓解压力','IPv6 主要依赖 NAT 扩展地址空间','C','IPv4 是 32 位地址，采用点分十进制表示，地址资源已枯竭，可通过 NAT 技术缓解压力；IPv6 是 128 位地址，采用冒分十六进制表示。','IPv4、IPv6 与 NAT',3,5,1,'2026-04-18 20:07:51','2026-04-18 20:07:51'),(141,15,'SINGLE','哪一项最符合动态路由的特点？','手动配置路由表，适用于小型网络','通过路由协议自动更新路由表','只能用于自治系统之间的路由','只能配合子网掩码使用','B','动态路由的核心特点是通过路由协议自动更新路由表。手动配置路由表是静态路由的特点；自治系统间路由协议只是动态路由中的一种应用场景。','静态路由与动态路由',3,5,2,'2026-04-18 20:07:51','2026-04-18 20:07:51'),(142,15,'SINGLE','对可靠性要求高的文件传输场景，通常应优先选择哪种协议？','UDP，因为其无连接且低延迟','TCP，因为其可保障数据完整性','UDP，因为其支持三次握手','HTTP/2，因为其属于传输层协议','B','TCP 提供可靠传输，通过建立连接并保障数据完整性，适用于文件传输等对可靠性要求高的场景。UDP 无连接、低延迟，但不保证可靠性。','TCP 与 UDP 的应用场景',3,5,3,'2026-04-18 20:07:51','2026-04-18 20:07:51'),(143,15,'SINGLE','HTTP/2 相比 HTTP/1.1 的改进主要体现在哪一项？','取消持久连接，减少连接占用','采用二进制帧和多路复用，提升并发性能','改为基于 UDP，完全避免时延','仅用于 DNS 查询优化','B','HTTP/2 采用二进制帧和多路复用技术，用于提升并发性能，并解决资料中提到的 HTTP/1.1 队头阻塞问题。','HTTP/1.1 与 HTTP/2 的区别',3,5,4,'2026-04-18 20:07:51','2026-04-18 20:07:51'),(144,15,'SINGLE','零信任架构的核心理念是哪一项？','一次认证，永久信任','内网可信，外网不可信','永不信任，始终验证','优先开放全部访问权限以提高效率','C','零信任架构强调“永不信任，始终验证”，并基于最小权限原则，对每个访问请求进行身份认证和权限校验。','零信任架构',3,5,5,'2026-04-18 20:07:51','2026-04-18 20:07:51'),(145,16,'SINGLE','Java实现跨平台运行的核心依赖是？','Java虚拟机（JVM）','Java编译器','垃圾回收机制','多线程机制','A','Java的跨平台特性依赖JVM实现，JVM屏蔽了不同操作系统的底层差异，使得编译后的字节码文件可以在任意安装了对应JVM的平台上运行，实现一次编写到处运行。','Java语言跨平台特性',3,5,1,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(146,16,'SINGLE','Java中byte类型的取值范围是？','-128 ~ 127','-32768 ~ 32767','0 ~ 255','-2³¹ ~ 2³¹-1','A','Java中byte是8种基本数据类型之一，占用1字节空间，取值范围为-128到127。','Java基本数据类型取值范围',3,5,2,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(147,16,'SINGLE','下列List接口的实现类中，查询速度快、增删速度慢的是？','ArrayList','LinkedList','HashSet','HashMap','A','ArrayList基于数组实现，支持随机访问因此查询速度快，但增删操作需要移动数组元素，因此增删速度慢；LinkedList基于链表实现，特性相反。','List接口常用实现类特性',3,5,3,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(148,16,'SINGLE','需要频繁修改字符串内容时，推荐使用以下哪个类？','String','StringBuilder','Integer','LocalDate','B','String是不可变字符序列，每次修改都会创建新对象，频繁修改会产生大量冗余对象，因此推荐使用StringBuilder（非线程安全）或StringBuffer（线程安全）。','String类特性',3,5,4,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(149,16,'SINGLE','下列Java线程创建方式中，能获取线程执行返回值的是？','继承Thread类','实现Runnable接口','实现Callable接口','以上都不能','C','Callable接口的call方法支持返回值，可配合FutureTask类获取线程的执行结果，Thread和Runnable的run方法无返回值。','多线程创建方式',3,5,5,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(150,16,'JUDGE','Java允许一个子类继承多个直接父类。','正确','错误',NULL,NULL,'错误','Java只支持单继承，一个子类只能有一个直接父类，可通过实现多个接口达到类似多继承的效果。','Java继承特性',3,3,6,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(151,16,'JUDGE','try-catch-finally结构中，finally块的代码只有在捕获到异常时才会执行。','正确','错误',NULL,NULL,'错误','finally块无论是否捕获到异常都会执行，通常用于资源释放等操作。','异常处理try-catch-finally机制',3,3,7,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(152,16,'JUDGE','@Override注解用于标识被修饰的方法已过时，调用时会收到编译器警告。','正确','错误',NULL,NULL,'错误','@Override注解用于标识方法重写了父类或接口的方法，@Deprecated注解才用于标识方法已过时。','Java内置注解作用',3,3,8,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(153,16,'SHORT_ANSWER','请简述面向对象编程的三大核心特性。',NULL,NULL,NULL,NULL,'面向对象编程三大核心特性为：1.封装：将对象的属性私有化，通过公共的getter/setter方法控制访问，隐藏内部实现细节提升安全性；2.继承：子类可继承父类的属性和方法，可扩展新功能或重写父类方法，实现代码复用；3.多态：同一个方法在不同场景下有不同的实现效果，可通过重写、重载等方式实现。','需明确答出封装、继承、多态三个特性，并对每个特性做基础解释。','面向对象核心特性',3,10,9,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(154,16,'SHORT_ANSWER','请简述Java异常体系中Error和Exception的区别。',NULL,NULL,NULL,NULL,'Error属于严重系统级错误，如虚拟机内存溢出、类加载错误等，程序无法主动处理这类错误；Exception属于程序运行时可处理的异常，如空指针异常、数组越界异常等，可通过try-catch、throws等机制进行捕获和处理，避免程序直接崩溃。','需明确说明Error是不可处理的严重错误，Exception是可处理的程序异常即可。','Java异常体系分类',3,10,10,'2026-04-20 14:08:38','2026-04-20 14:08:38'),(155,17,'SINGLE','Docker容器的隔离级别是？','进程级隔离','完全隔离','内核级隔离','用户级隔离','A','Docker容器为进程级隔离，传统虚拟机为完全隔离，进程级隔离的方案更轻量，启动速度更快。','Docker与传统虚拟机的核心区别',3,5,1,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(156,17,'SINGLE','Docker中用于实现资源隔离（进程、网络、文件系统等）的底层技术是？','Namespace','Cgroups','Union FS','containerd','A','Namespace用于实现资源隔离，Cgroups用于实现资源限制，Union FS用于实现分层存储，containerd是容器运行时引擎。','Docker底层核心技术',3,5,2,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(157,17,'SINGLE','下列关于Dockerfile中CMD指令的写法，符合最佳实践的是？','CMD [\"python\", \"app.py\"]','CMD [\'python\', \'app.py\']','CMD service nginx start','CMD systemctl start nginx','A','CMD指令优先使用exec格式，需使用双引号（JSON不支持单引号），且需确保应用在前台运行，禁止使用后台服务启动命令。','Dockerfile CMD指令最佳实践',3,5,3,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(158,17,'SINGLE','Kubernetes的最小调度单位是？','Pod','Node','Deployment','Service','A','Pod是Kubernetes的最小调度单位，一个Pod可以包含一个或多个紧密协作的容器，共享网络和存储。','Kubernetes核心概念',3,5,4,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(159,17,'SINGLE','下列安全容器运行时方案中，通过轻量级虚拟机实现独立内核隔离的是？','Kata Containers','gVisor','runc','containerd','A','Kata Containers使用轻量级虚拟机实现独立内核的硬件级虚拟化隔离，gVisor通过用户态内核拦截系统调用实现隔离，runc是标准Linux容器运行时。','安全容器运行时方案',3,5,5,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(160,17,'SINGLE','如果需要远程访问Docker守护进程，开启TLS认证后应监听的安全端口是？','2376','2375','8080','2379','A','无认证的2375端口禁止暴露在公网，开启TLS认证的安全远程访问端口为2376。','Docker服务端安全防护',3,5,6,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(161,17,'SINGLE','下列容器性能指标中，属于内存相关指标的是？','memory.usage_bytes','cpu.usage_usec','cpu.stat.throttled_usec','cpu_percent','A','memory.usage_bytes代表容器当前内存使用量，其余三个选项均属于CPU相关性能指标。','容器性能监控指标',3,5,7,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(162,17,'SINGLE','如果需要部署微服务应用，追求镜像体积小且拥有包管理器，应选择的基础镜像是？','Alpine','Busybox','CentOS','Debian','A','Alpine镜像大小约5MB，使用apk包管理器，适合微服务、静态应用场景；Busybox无包管理器，CentOS、Debian镜像体积远大于Alpine。','Docker常用基础镜像选型',3,5,8,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(163,17,'SINGLE','下列Docker网络驱动中，使用宿主机网络栈、性能最优的是？','Host','Bridge','Overlay','macvlan','A','Host网络驱动使用宿主机网络栈，性能最优但隔离性最差；Bridge是默认网络驱动，Overlay用于跨主机通信，macvlan可让容器获得独立MAC地址。','Docker网络驱动区别',3,5,9,'2026-04-20 14:12:16','2026-04-20 14:12:16'),(164,17,'SINGLE','在Dockerfile中，用于定义容器可执行程序，运行时参数会追加而非覆盖的指令是？','ENTRYPOINT','CMD','RUN','WORKDIR','A','ENTRYPOINT用于定义容器的可执行程序，运行时传入的参数会追加到指令后；CMD定义的是容器默认命令，运行时可被覆盖；RUN用于执行构建时命令，WORKDIR用于指定工作目录。','Dockerfile ENTRYPOINT指令作用',3,5,10,'2026-04-20 14:12:16','2026-04-20 14:12:16');
